INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES ('Dell Publishing was an American publisher of books and comic books, founded in 1921. They would partner with Western Publishing as their printer from 1938 to 1962 and many of their titles would later continue with Western as a result. Dell almost entirely ceased its comic publishing by the early 70''s and became a smaller company bought and divvied up by larger book publishers.', '<p>George T. Delacorte Jr. started the company with $10.000, two employees and one magazine called ''I Confess'', which was soon followed by pulp magazines. During the 1920s - 1940s Dell Publishing was one of the largest magazine publishers. From 1938-1962 they published comics under their imprint name of Dell Comics, most of which were done in partnership with <a href="/western-publishing/4010-178/" data-ref-id="4010-178">Western Publishing</a>. They started paperback book publishing in 1943 with their new imprint called Dell Paperbacks. Their imprint line grew and they started bringing out books under the names of: Dial Press, Delacorte Books, Yearling Books and Laurel Leaf Library.</p><p>Dell Publishing were bought out and are now part of the Bantam Dell Publishing Group of <a href="/random-house/4010-1350/" data-ref-id="4010-1350">Random House</a>. They are still using some of the imprints Dell Publishing started. Dell Magazines was sold in 1997. To this day it still publishes puzzle, mystery, horoscope and science fiction magazines.</p><h4>Comic characters</h4><p>Some of the stable of characters that were originally published by Dell or published in partnership with Western Publishing were</p><ul><li>Black Knight (Dell version)</li><li>Brain Boy (Dell, Dark Horse)</li><li>Captain Easy</li><li><a href="/martan-the-marvel-man/4005-18747/" data-ref-id="4005-18747">Martan the Marvel Man</a> and Vana (Dell, Dynamite)</li><li>Triple Terror (United Features, Dell)</li><li><a href="/phantasmo/4005-62026/" data-ref-id="4005-62026">Phantasmo</a> (Dell, Dynamite)</li><li><a href="/professor-supermind/4005-74335/" data-ref-id="4005-74335">Professor Supermind and Son</a> (Dell, Dynamite)</li><li>The Voice, Invisible Detective (Quality, Dell)</li><li><a href="/the-owl/4005-46596/" data-ref-id="4005-46596">The Owl</a> and Owl Girl (Dell, Gold Key, Dynamite)</li><li>Owl Girl (Dell, Gold Key, Dynamite)</li><li><a href="/captain-midnight/4050-23322/" data-ref-id="4050-23322">Captain Midnight</a> (Fawcett, Dell, Moonstone, Dark Horse)</li><li>Captain Tornado</li><li>Dan Dunn (The other Dick Tracy) (Eastern Color, Dell, Gold Key)</li><li>Doctor Death I, II (Dell version)</li><li>Doctor Hammond</li><li>Gray Mask and Dove</li><li>Green Lama (Prize, Spark, Dell, Moonstone, Dynamite)</li><li>John Carter, Warlord of Mars (Dell, Gold Key, DC, Marvel, Dynamite)</li><li>Deja Thoris (Dell, Marvel, Dark Horse, Dynamite)</li><li>Jungle Jim (Alex Raymond creation) (King Features, Nedor, Dell, Charlton, Dynamite)</li><li>Lothar (King Features, Harvey, Dell, Marvel, Dynamite)</li><li>Magic Morro</li><li>Mandrake the Magician (United Features, Harvey, Dell, Marvel, Moonstone, Dynamite)</li><li>Masked Pilot</li><li>Ming the Merciless (United Features, Toby Press, Eastern Color, Dell, Gold Key, Harvey, Charlton, Marvel, DC, Dynamite)</li><li>Mr. Ozymandias</li><li><a href="/the-night-devils/4060-58000/" data-ref-id="4060-58000">Night Devils</a> aka Black Wings</li><li>Pantherman</li><li>Phantom Raider of the Sky</li><li>Radior: The X-Ray Powerman (Dell, Dynamite)</li><li>Red Ryder</li><li>Ricota</li><li>Scarlet Ace (Dell version)</li><li>Scarlet Ace (Pulp)</li><li>Sikander, the Robot Master</li><li>Skyhawk (Dell version)</li><li>Sky Ranger</li><li>Space Man</li><li>Speed Martin</li><li>Stratosphere Jim</li><li>Viking Carter</li><li>X5328B</li><li>Young Hawk</li><li><a href="/nukla/4005-61231/" data-ref-id="4005-61231">Nukla</a></li><li><a href="/brain-boy/4005-5609/" data-ref-id="4005-5609">Brain Boy</a> (Dell, Dark Horse)</li><li><a href="/neutro/4005-61232/" data-ref-id="4005-61232">Neutro</a></li><li>Fab Four</li><li><a href="/kona/4005-13931/" data-ref-id="4005-13931">Kona</a>, Monarch of Monster Isle</li><li>Flash Gordon (United Features, Toby, Eastern Color, Dell, Gold Key, Harvey, Charlton, Marvel, DC, Dynamite)</li><li>Tarzan (Dell, Gold Key, DC, Marvel, Dark Horse, Dynamite)</li><li>The Lone Ranger (Dell, Gold Key, Dynamite)</li><li>Tom Corbett (Prize, Dell, Blue Water)</li><li>Zorro (Quality,Dell, Gold Key, Dynamite)</li><li>Turok (Dell, Gold Key, Valiant, Dark Horse, Dynamite)</li><li>Andar (Dell. Gold Key, Valiant, Dark Horse, Dynamite)</li></ul>', '4', 'Dell', '[{"id": 47791}, {"id": 56310}, {"id": 56331}, {"id": 56624}, {"id": 56708}, {"id": 58000}, {"id": 58811}, {"id": 60031}, {"id": 60058}, {"id": 60059}, {"id": 60117}, {"id": 61801}, {"id": 66269}]', '[{"id": 777}, {"id": 778}, {"id": 927}, {"id": 1098}, {"id": 1172}, {"id": 1246}, {"id": 1247}, {"id": 1331}, {"id": 1408}, {"id": 1409}, {"id": 1478}, {"id": 1479}, {"id": 1557}, {"id": 1562}, {"id": 1621}, {"id": 1622}, {"id": 1688}, {"id": 1693}, {"id": 1777}, {"id": 1825}, {"id": 1869}, {"id": 1875}, {"id": 1876}, {"id": 1999}, {"id": 2000}, {"id": 2002}, {"id": 2018}, {"id": 2019}, {"id": 2020}, {"id": 2021}, {"id": 2035}, {"id": 2036}, {"id": 2037}, {"id": 2040}, {"id": 2055}, {"id": 2058}, {"id": 2059}, {"id": 2060}, {"id": 2062}, {"id": 2066}, {"id": 2067}, {"id": 2070}, {"id": 2072}, {"id": 2074}, {"id": 2117}, {"id": 2119}, {"id": 2180}, {"id": 2181}, {"id": 2183}, {"id": 2184}, {"id": 2185}, {"id": 2187}, {"id": 2226}, {"id": 2228}, {"id": 2229}, {"id": 2280}, {"id": 2281}, {"id": 2282}, {"id": 2340}, {"id": 2341}, {"id": 2344}, {"id": 2347}, {"id": 2348}, {"id": 2349}, {"id": 2440}, {"id": 2468}, {"id": 6500}, {"id": 6574}, {"id": 6575}, {"id": 6576}, {"id": 6806}, {"id": 9557}, {"id": 9627}, {"id": 10720}, {"id": 10727}, {"id": 10734}, {"id": 10739}, {"id": 10834}, {"id