INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES ('One of the most famous newspaper comic strip syndicates, for a time in the Golden Age they published work in the standard comic format.', '<p>United Features had three heroes that they published:</p><ul><li><a href="/iron-vic/4005-9280/" data-ref-id="4005-9280">Iron Vic</a></li><li><a href="/mirror-man/4005-67513/" data-ref-id="4005-67513">Mirror Man</a> (United Features version)</li><li><a href="/spark-man/4005-61814/" data-ref-id="4005-61814">Spark Man</a> (United Features, Dynamite)</li><li><a href="/tarzan/4005-22892/" data-ref-id="4005-22892">Tarzan</a> (United Features, Dell. DC, Marvel, Dynamite)</li><li><a href="/triple-terror/4060-65438/" data-ref-id="4060-65438">Triple Terror</a> (United Features, Dell)</li></ul><p>Spark Man is the only hero from United Features revived by <a href="/dynamite-entertainment/4010-1859/" data-ref-id="4010-1859">Dynamite Entertainment </a>under their <a href="/project-superpowers/4050-20326/" data-ref-id="4050-20326">Project Superpowers</a> title.</p><p>Tarzan was also published by United Features for a time. Tarzan would be revived in Dell''s Four Color title.</p>', '5', 'United Feature Syndicate', '[{"id": 56568}, {"id": 64739}, {"id": 65438}]', '[{"id": 766}, {"id": 874}, {"id": 1831}, {"id": 9490}, {"id": 29704}, {"id": 30942}, {"id": 31267}, {"id": 31311}, {"id": 31506}, {"id": 31814}, {"id": 31895}, {"id": 42321}, {"id": 46011}, {"id": 57453}, {"id": 57769}, {"id": 63184}, {"id": 66861}, {"id": 70215}, {"id": 70236}, {"id": 71417}, {"id": 71698}, {"id": 88155}, {"id": 88167}, {"id": 88172}, {"id": 141227}, {"id": 152627}]', 'https://comicvine.gamespot.com/a/uploads/screen_medium/1/15776/8658015-unitedfeaturesyndicate.jpg');
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES ('A pulp magazine and comic book publisher in the Golden Age of Comics.', '<p>(Fiction House was a big time publisher of both pulp magazines and comic books from the 1920s to the 1950s. Its comics division was best known for its pinup-style good girl art, as epitomized by the company''s most popular character <a href="/sheena/4005-31442/" data-ref-id="4005-31442">Sheena, Queen of the Jungle</a>. Fiction House also launched the careers of <a href="/jack-kirby/4040-5614/" data-ref-id="4040-5614">Jack Kirby</a> and <a href="/will-eisner/4040-26686/" data-ref-id="4040-26686">Will Eisner</a> as well. The publisher was also a target of <a href="/fredric-wertham/4005-6619/" data-ref-id="4005-6619">Dr. Fredric Wertham</a>''s infamous book Seduction of the Innocent in 1954.</p><p>Some of the stable of characters that were originally published by Fiction House were</p><p>Agent ZX-5</p><p>Akina</p><p>Amazona the Mighty Woman</p><p>Angel Eyes</p><p>Ant Woman</p><p>Auro, Lord of Jupiter I, II</p><p>Black Axeman</p><p>Blaque</p><p>Bron</p><p>Bob Reynolds (sidekick to Sheena)</p><p>Bull''s Eye Brannon</p><p>Buzz Crandall</p><p>Camilla</p><p>Camilla, Queen of the City</p><p>Captain Fight and Yank Adams</p><p>Captain Fight (Pirate)</p><p>Captain Morgan''s U.S. Rangers or Sky Rangers</p><p>Captain Nelson Cole</p><p>Captain Plastic (on cover)</p><p>Captain Tiger</p><p>Captain Thunder (Fawcett changed their character to Captain Marvel)</p><p>Captain Wings</p><p>Cerberex (look inspired Brainiac''s ship)</p><p>Chip Collins and his Skull Squadron</p><p>Colonel Kamikaze</p><p>Commando Ranger</p><p>Commander Cubs</p><p>Cosmo Corrigan</p><p>Crash Parker</p><p>Crimson Cobra</p><p>Crossbow Crew</p><p>Dexter Ames</p><p>Domino Lady (Fiction House, Moonstone) Lady Domino Saucy Romantic Adventures May 1936 First Appearance</p><p>Dr. Drew (Fiction House, Dark Horse)</p><p>Dr. Shelley</p><p>The Eye (Fiction House version)</p><p>El Cuchillo</p><p>Fantomah (Fiction House, Devil''s Due)</p><p>Fantomah, Daughter of the Pharohs</p><p>Fero, Planet Detective</p><p>Firehair (Fiction House version)</p><p>Flint Baker</p><p>Frosty North</p><p>Futura</p><p>Gale Allen and her Girl Squadron</p><p>Ghazia</p><p>G. I. Jane (Fiction House version)</p><p>Goliath the Gladiator</p><p>The Hawk</p><p>Hunt Bowman</p><p>Ibid and Noxid</p><p>Inspector Dayton</p><p>Jan of the Jungle</p><p>Jane Martin</p><p>Jim Grant</p><p>Jungle Demon</p><p>Kaänga, Jungle King and Ann Mason</p><p>Kazanda, Wild Girl of the Continent</p><p>Ki-Gor, Jungle Lord (Fiction House, Moonstone)</p><p>King Tonga</p><p>Kinks Mason</p><p>Leopard Men</p><p>Lightning (Fiction House version)</p><p>Lone Wolf and Little Wolf</p><p>Long Bow (Fiction House version)</p><p>Lustra</p><p>Madame Terror</p><p>Madame Zero</p><p>Man ''O Mars</p><p>Manzar</p><p>Mark Lord</p><p>Mandoor</p><p>Mysta of The Moon</p><p>Oran of the Jungle</p><p>The Phantom Falcon (Fiction House, Holyoke, Moonstone)</p><p>Phantom Falcons</p><p>Planet Payson</p><p>Rangers of Freedom</p><p>Red Comet</p><p>Red Panther</p><p>Reef Ryan</p><p>Rip Regan Power-Man</p><p>Rocky Hall, Jungle Explorer</p><p>Roy Lance, Jungle Explorer</p><p>Saber, the Spy Hunter</p><p>Sarko</p><p>Sea Devil (Fiction House version)</p><p>Senorita Rio</p><p>Shark Brodie</p><p>Sheena, Queen of The Jungle (Fiction House, Devil''s Due, Moonstone, Dynamite) (created by Will Eisner and Jerry Iger)</p><p>Sky Girl</p><p>Spurt Hammond</p><p>The Spy Fighter</p><p>Star Pirate</p><p>Stuart Taylor</p><p>Suicide Smith</p><p>Super American (Fiction House, Dynamite)</p><p>Super-Brain and his Super Gorillas</p><p>Sylf</p><p>Tabu, Wizard of the Jungle (Fiction House version)</p><p>Tiger Girl (Fiction House version)</p><p>Tiger Hart</p><p>Tiger Man (Fiction House version)</p><p>The Spirit (Quality, Fiction House, Harvey, Dark Horse, DC, Dynamite)</p><p>Tortug</p><p>Werewolf Hunter</p><p>White Panther</p><p>X-7 of the British Intelligence</p><p>Yrina</p><p>Zan Marzov</p><p>Many of the characters have seperate pages while others do not.</p>', '8', 'Fiction House', '[{"id": 58036}, {"id": 58037}, {"id": 58038}, {"id": 58040}, {"id": 58041}, {"id": 58042}, {"id": 58044}, {"id": 58184}, {"id": 58185}, {"id": 58186}, {"id": 58187}, {"id": 58188}, {"id": 58189}, {"id": 58190}, {"id": 58193}, {"id": 58194}]', '[{"id": 769}, {"id": 816}, {"id": 879}, {"id": 1483}, {"id": 11348}, {"id": 11349}, {"id": 11594}, {"id": 18555}, {"id": 19318}, {"id": 19431}, {"id": 19564}, {"id": 19568}, {"id": 19593}, {"id": 19662}, {"id": 21052}, {"id": 23884}, {"id": 26039}, {"id": 27195}, {"id": 27196}, {"id": 33936}, {"id": 34178}, {"id": 34179}, {"id": 39686}, {"id": 49328}, {"id": 49353}, {"id": 49354}, {"id": 64142}, {"id": 64143}, {"id": 66534}, {"id": 66606}, {"id": 70329}, {"id": 82288}, {"id": 88067}, {"id": 96247}, {"id": 135706}]', 'https://comicvine.gamespot.com/a/uploads/screen_medium/6/69951/1387073-fiction_house.jpg');
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES ('Originally known as "National Publications", DC is a publisher of comic books featuring iconic characters and teams such as Superman, Batman, Wonder Woman, Green Lantern, the Justice League of America, and the Teen Titans, and is considered the originator of the American superhero genre. DC, along with rival Marvel Comics, is one of the "big two" American comic book publishers. DC Entertainment is a subsidiary of Warner Brothers and its parent company Warner Media.', '<h2>Current Personnel</h2><ul><li><a href="/diane-nelson/4040-60224/" data-ref-id="4040-60224">Diane Nelson</a>: President</li><li><a href="/jim-lee/4040-2399/" data-ref-id="4040-2399">Jim Lee</a> &amp; <a href="/dan-didio/4040-51584/" data-ref-id="4040-51584">Dan Didio</a>: Co-Publishers</li><li><a href="/bob-harras/4040-40985/" data-ref-id="4040-40985">Bob Harras</a>: Editor-In-Chief</li><li><a href="/geoff-johns/4040-40439/" data-ref-id="4040-40439">Geoff Johns</a>: Chief Creative Officer</li><li><a href="/john-rood/4040-71914/" data-ref-id="4040-71914">John Rood</a>: Executive Vice President, Sales, Marketing and Business Development</li></ul><h2><strong>History</strong></h2><p>What is known today as DC Comics was founded in 1934 by publishing entrepreneur <a href="/malcolm-wheeler-nicholson/4040-43628/" data-ref-id="4040-43628">Malcolm Wheeler-Nicholson</a> under the name of "National Allied Publications". DC was formed by the merging of "National Allied Publications" and "Detective Comics Inc", as well as the affiliated "All-American Publications". Despite being officially known as "National Comics", the comic covers carried a "DC" logo and were referred to as a result of its nickname: "DC Comics". People had nicknamed it "DC" in reference to Distinct of Columbia in Washington, due to the extreme patriotism during a time of war. Thus was born one of the world''s most recognizable comic book brandings along with rivals <a href="/marvel/4010-31/" data-ref-id="4010-31">Marvel</a> publishing.</p><p>The company did not officially change its name to DC Comics however, until 1977 during the presidency of <a href="/jenette-kahn/4040-47576/" data-ref-id="4040-47576">Jenette Kahn</a>.</p><p>DC Comics has its current official headquarters at 1700 Broadway, 7th, New York, New York. Random House distributes DC Comics'' books to the bookstore market, while Diamond Comics Distributors supplies the comics shop specialty market.</p><h3>Golden Age</h3><figure data-align="right" data-size="medium" data-img-src="https://static.comicvine.com/uploads/original/14/148518/2969569-dc%20house%20ad%2091412b.jpg" data-ref-id="1300-2969569" data-ratio="1.5287474332649" data-width="974" data-embed-type="image" style="width: 974px"><a class="fluid-height" style="padding-bottom:152.9%" href="https://static.comicvine.com/uploads/original/14/148518/2969569-dc%20house%20ad%2091412b.jpg" data-ref-id="1300-2969569"><img alt="No Caption Provided" src="https://comicvine.gamespot.com/a/uploads/scale_medium/14/148518/2969569-dc%20house%20ad%2091412b.jpg" srcset="https://comicvine.gamespot.com/a/uploads/original/14/148518/2969569-dc%20house%20ad%2091412b.jpg 974w, https://comicvine.gamespot.com/a/uploads/scale_medium/14/148518/2969569-dc%20house%20ad%2091412b.jpg 627w" sizes="(max-width: 627px) 100vw, 627px" data-width="627"></a></figure><p>National Allied Publications'' first comic was <a href="/new-fun-1-the-big-comic-magazine/4000-110666/" data-ref-id="4000-110666"><i>New Fun: The Big Comic Magazine #1</i></a> which was released in the February of 1935. It hit off, and was surprisingly popular. Later that year, a second title was released: <i><a href="/new-comics-1/4000-109779/" data-ref-id="4000-109779">New Comics #1</a>.</i> The size and length <i>New Comics #1</i> became the archetype for many comics afterwards, and it became the longest running comic series of all time.</p><p>In 1938, National launched<a href="/action-comics/4050-18005/" data-ref-id="4050-18005"><em> Action Comics</em></a>, which featured the brand new character from regular contributors <a href="/jerry-siegel/4040-40754/" data-ref-id="4040-40754">Jerry Siegel</a> and <a href="/joe-shuster/4040-40755/" data-ref-id="4040-40755">Joe Shuster</a>, <a href="//www.comicvine.com/superman/4005-1807/" data-ref-id="4005-1807">Superman</a>. Originally dismissed as "silly" by editorial, reports soon came back noting the popularity and sales increase resulting from the Superman feature. Superman quickly became a sensation and before long, dozens of imitations from both National and other publishing houses appeared almost overnight. Writer <a href="/bill-finger/4040-43591/" data-ref-id="4040-43591">Bill Finger</a> and his artist employer <a href="/bob-kane/4040-19137/" data-ref-id="4040-19137">Bob Kane</a> soon submitted <a href="//www.comicvine.com/batman/4005-1699/" data-ref-id="4005-1699">Batman</a> to appear in <a href="/detective-comics/4050-18058/" data-ref-id="4050-18058"><em>Detective Comics</em></a> and before long, an entire <a href="/justice-society-of-america/4060-27589/" data-ref-id="4060-27589">Justice Society of America</a> had been formed including properties such as <a href="/jay-garrick/4005-2395/" data-ref-id="4005-2395">The Flash</a>, <a href="/alan-scott/4005-12663/" data-ref-id="4005-12663">Green Lantern</a>, <a href="/wesley-dodds/4005-9299/" data-ref-id="4005-9299">The Sandman</a>, <a href="//www.comicvine.com/wonder-woman/4005-2048/" data-ref-id="4005-2048">Wonder Woman</a>, <a href="/hawkman/4005-8337/" data-ref-id="4005-8337">Hawkman</a> and <a href="/spectre/4005-2361/" data-ref-id="4005-2361">The Spectre</a>, to name a few, many of whom were either created or written by the prolific <a href="/gardner-fox/4040-41171/" data-ref-id="4040-41171">Gardner Fox</a>.</p><p>With the establishment of DC as one of the major comic book companies and with many of the most marketable names in the early years of comics, it is sometimes considered the main company that other companies had to compete with. Companies tried different approaches, One that succeeded and often outsold DC for instance was <a href="/fawcett-publications/4010-34/" data-ref-id="4010-34">Fawcett Publications</a> who had a character who some consider similar to <a href="/superman/4005-1807/" data-ref-id="4005-1807">Superman</a> who was an all-powerful hero with a supporting "family" known as <a href="//www.comicvine.com/billy-batson/4005-2350/" data-ref-id="4005-2350">Captain Marvel and the Marvel Family,</a> whereas other companies such as <a href="/charlton/4010-125/" data-ref-id="4010-125">Charlton Comics</a> created entire new worlds preventing DC from attacking them with lawsuits. Further along in the <a href="/silver-age-of-comics/4015-55821/" data-ref-id="4015-55821">Silver Age</a> many of these companies failed or like Fawcett were sued out of existence. Thus although they had once been competitors, many of the soon public domain properties of Fawcett and Charlton were eventually revived and trademarked and seemingly taken under DC''s control.</p><h3>Silver &amp; Bronze Age</h3><p>During the post-War years, the popularity of superheroes had declined almost completely, though DC and other publishers were still going strong moving into other genres such as funny animals, romance, Sci-Fi, Westerns and horror. Major characters such as Batman, Wonder Woman and Superman has managed to remain in publication and by the mid-1950s the superhero was again due for a comeback. <a href="/showcase-4-mystery-of-the-human-thunderbolt-the-ma/4000-2653/" data-ref-id="4000-2653"><em>Showcase #4</em></a> in 1956 introduced readers to Barry Allen, the all-new Flash re-imagined with a sleeker design and steeped much heavier in science fiction (an the older Golden Age heroes being relegated to existing on Earth Two). Characters such as The Atom, Green Lantern and the JSA, now reinvented as the Justice League of America soon followed and a new superhero boom was kicked off.</p><p>During this time, The <a href="/comics-code-authority/4015-42382/" data-ref-id="4015-42382">Comics Code Authority</a> has also come into play, which drastically subdued the content available in the comic book medium. Many of the stories during the period moved away from more controversial horror or violent themes.</p><p>With the re-invigoration of Marvel in the 1960s under the leadership of <a href="/stan-lee/4040-40467/" data-ref-id="4040-40467">Stan Lee</a> and <a href="/jack-kirby/4040-5614/" data-ref-id="4040-5614">Jack Kirby</a>, DC found itself a new and more potent competitor. Marvel succeeded by breaking what had become by then generic archetypes of superheroes by introducing characters which were younger and more flawed (and thus appeared more human and appealed to a younger crowd in a more direct manner.) After falling behind Marvel in sales, DC was finally forced to adopt much of the same system which Marvel had, by introducing such young teams as the <a href="/teen-titans/4060-19081/" data-ref-id="4060-19081">Teen Titans</a> to compete with the <a href="/x-men/4060-3173/" data-ref-id="4060-3173">X-Men</a>.</p><h3>Modern Age &amp; Crisis on Infinite Earths</h3><figure data-align="right" data-size="medium" data-img-src="https://static.comicvine.com/uploads/original/14/148518/2959713-dc%20previews%20poster.jpg" data-ref-id="1300-2959713" data-ratio="1.3491436100132" data-width="759" data-embed-type="image" style="width: 759px"><a class="fluid-height" style="padding-bottom:134.9%" href="https://static.comicvine.com/uploads/original/14/148518/2959713-dc%20previews%20poster.jpg" data-ref-id="1300-2959713"><img alt="The Modern Age" src="https://comicvine.gamespot.com/a/uploads/scale_medium/14/148518/2959713-dc%20previews%20poster.jpg" srcset="https://comicvine.gamespot.com/a/uploads/original/14/148518/2959713-dc%20previews%20poster.jpg 759w, https://comicvine.gamespot.com/a/uploads/scale_medium/14/148518/2959713-dc%20previews%20poster.jpg 711w" sizes="(max-width: 711px) 100vw, 711px" data-width="711"></a><figcaption>The Modern Age</figcaption></figure><p>In 1985, DC Comics decided its 50 years of continuity and numerous alternative Earths had become too messy and was in need of new blank slate. DC penned one of the first major comic book crossovers that incorporated almost every DC title and character ever published by the company. The series ended with multiple Earths being erased and merging into to one unified Earth. Following this, Batman, Superman and Wonder Woman were given new leases of life thanks to big name creators such as John Byrne, Frank Miller and <a href="/george-perez/4040-2913/" data-ref-id="4040-2913">George Perez</a> that redefined the elderly heroes for a new generation.</p><p>During this same period, the comic audience has begun to grow up and the direct market for comic stores had opened allowing a wider variety of publications to be experimented with. One such experiment involved bringing in British writer Alan Moore to pen the low selling <em>Saga of the Swamp Thing</em> series. What resulted was style of comic book not experienced before by mainstream readers in its literary and story driven complexity and execution. Before long, other writers from across the pond such as Neil Gaiman, Peter Milligan and Grant Morrison were recruited to revamp obscure properties and tell new and interesting stories with an older audience in mind. 1986 saw the release of two seminal works from DC Comics, Frank Miller''s <em>The Dark Knight Returns</em> and Alan Moore''s <em>Watchmen</em> that reached unprecedented levels of critical acclaim and outside media attention. By the 90''s DC and the entire comic book industry experienced a boom in mature comics aimed at older audiences and simultaneously witnessed a collector''s boom that increased sales but almost caused the industry to collapse soon after.</p><p>In 1993, senior editor Karen Berger convinced DC to make her own imprint for mature readers named <a href="/vertigo/4010-521/" data-ref-id="4010-521">Vertigo</a>, similar to DC imprints <a href="/piranha-press/4015-58392/" data-ref-id="4015-58392">Piranha Press</a> and <a href="/paradox-press/4015-58397/" data-ref-id="4015-58397">Paradox Press</a> as well as Marvel''s <a href="/epic/4015-58417/" data-ref-id="4015-58417">Epic Comics</a>. Using popular titles such as <a href="/animal-man/4050-3976/" data-ref-id="4050-3976"><em>Animal Man</em></a>, <a href="/swamp-thing/4050-3465/" data-ref-id="4050-3465"><em>Swamp Thing</em></a>, <a href="/hellblazer/4050-4008/" data-ref-id="4050-4008"><em>Hellblazer</em></a>, <a href="/the-sandman/4050-4207/" data-ref-id="4050-4207"><em>The Sandman</em></a> and <a href="/shade-the-changing-man/4050-4375/" data-ref-id="4050-4375"><em>Shade, The Changing Man</em></a> as its blueprint along side new creator owned material, DC/Vertigo became a hub for intelligent and acclaimed comic books. While rival Marvel Comics continued to dominate the publishing arena with their exceedingly popular properties, DC/Vertigo became the destination for literary and inventive titles during the period.</p><p>In 1999, DC purchased Jim Lee''s <a href="/wildstorm/4010-708/" data-ref-id="4010-708">WildStorm Productions</a>, formerly one of the founding studios of <a href="/image/4010-513/" data-ref-id="4010-513">Image</a>. The line of WildStorm comics and properties came under DC''s control though the line continued to be published on the West Coast away from DC editorial until 2010.</p><h3>All Star DC Comics</h3><p>In 2000 Marvel Comics started an imprint called ultimate marvel in which the characters'' origin is changed and modernized. This eventually led DC to starting an imprint of their own in 2005, thus All Star was born.</p><p>Both All-Star series are in their own continuity, except <em>All-Star Batman and Robin</em> which was part of <a href="//www.comicvine.com/earth-31/4020-57575/" data-ref-id="4020-57575">Earth- 31</a>.</p><p><strong>All Star Batman and Robin the Boy Wonder</strong></p><p><em>All-Star Batman</em> started in 2005 and was written by Frank Miller and Penciled by Jim Lee. This was the first series in the All Star imprint and opened to mainly negative reviews but had high sales. The series was released in a sporadic schedule. The series only reached 10 issues (2008) 2 issues before the intended end of the series.</p><p><strong>All Star Superman</strong></p><p><em>All-Star Superman</em> started in 2006 and was written by Grant Morrison and Penciled by Frank Quitley. This was the second series under the All Star imprint, the first being <em>All-Star Batman and Robin</em>. The series opened to mainly good reviews and went on to win the Eisner Award for best new series in 2006 and best ongoing series in 2007 and 2009. Like <em>All-Star Batman</em> the series was also released in a sporadic schedule. The series ended with issue 12. The series overall has widely considered to be one of the best Superman stories of all time.</p><h3>The New 52</h3><figure data-align="right" data-img-src="https://static.comicvine.com/uploads/original/5/58664/1837076-dc_comics_reinvents_pg564mg_x_large.jpg" data-ref-id="1300-1837076" data-size="small" data-ratio="0.73469387755102" data-width="490" data-embed-type="image" style="width: 490px"><a class="fluid-height" style="padding-bottom:73.5%" href="https://static.comicvine.com/uploads/original/5/58664/1837076-dc_comics_reinvents_pg564mg_x_large.jpg" data-ref-id="1300-1837076"><img alt="Justice League # 1" src="data:image/gif;base64,R0lGODlhAQABAAAAACH5BAEKAAEALAAAAAABAAEAAAICTAEAOw==" sizes="(max-width: 320px) 100vw, 320px" data-width="320" class="js-lazy-load-image" data-src="https://comicvine.gamespot.com/a/bundles/phoenixsite/images/core/loose/img_broken.png" data-srcset="https://comicvine.gamespot.com/a/bundles/phoenixsite/images/core/loose/img_broken.png 490w, https://comicvine.gamespot.com/a/bundles/phoenixsite/images/core/loose/img_broken.png 480w, https://comicvine.gamespot.com/a/bundles/phoenixsite/images/core/loose/img_broken.png 320w"><noscript><img alt="Justice League # 1" src="https://comicvine.gamespot.com/a/bundles/phoenixsite/images/core/loose/img_broken.png" srcset="https://comicvine.gamespot.com/a/bundles/phoenixsite/images/core/loose/img_broken.png 490w, https://comicvine.gamespot.com/a/bundles/phoenixsite/images/core/loose/img_broken.png 480w, https://comicvine.gamespot.com/a/bundles/phoenixsite/images/core/loose/img_broken.png 320w" sizes="(max-width: 320px) 100vw, 320px" data-width="320"></noscript></a><figcaption>Justice League # 1</figcaption></figure><p>In 2011, after a period of declining comic sales, DC announced they were cancelling all the main titles and starting over with all <a href="/the-new-52/4015-56061/" data-ref-id="4015-56061">New 52''s</a> as part of a relaunch. In charge of the relaunch is <a href="/geoff-johns/4040-40439/" data-ref-id="4040-40439">Geoff Johns</a> and <a href="/jim-lee/4040-2399/" data-ref-id="4040-2399">Jim Lee</a>. The relaunch started with the release of <a href="/justice-league-justice-league-part-one/4000-290431/" data-ref-id="4000-290431"><em>Justice League</em> # 1</a> on August 31st. this was done partially to revitalize the company and to de-age the characters and thus make them more dynamic. On January 12, 2012, it was announced that there would be a second wave of the new 52 where six titles would be getting canceled with another six to replace them, though the plan to stay at 52 ongoing monthlies seems to be consistent. DC also released a Third wave in September 2012, one year after the relaunch in September 2011. One book in the Third Wave, <em>Talon</em>, starring Calvin Rose was the first solo book for a character who was introduced in the New 52. The Fourth wave started in January 2013 and ended in March 2013, meaning that it was the first wave not to come out in a single month. The Fifth Wave consisted of titles such as <em>the Movement</em>, <em>the Green Team</em> and <em>Superman Unchained</em>.</p><p>The New 52 had proved to be so successful with critics, fans and commercially that Marvel the main competitor of DC decided to do a relaunch of their own called "<a href="//www.comicvine.com/marvel-now/4015-56129/" data-ref-id="4015-56129">Marvel NOW!</a>" in late 2012.</p><h2><strong>Relocating from Manhattan to Burbank</strong></h2><p>In 2015, DC Entertainment moved their entire operations from their Manhattan headquarters in New York City to their new home in Burbank, California. DC''s digital and administrative departments had already been relocated to Burbank beginning in 2010. The new office is only a few blocks from their corporate parent company, Warner Bros. Studios.</p><h2><b>DC Imprints and Sub-Imprints</b></h2><p><strong>Active</strong></p><ul><li><a href="/vertigo/4015-58432/" data-ref-id="4015-58432">Vertigo</a> (1993-)</li><li><a href="/mad/4050-9318/" data-ref-id="4050-9318">MAD/ MAD Magazine</a> (Acquired by Warner in the 60''s, integrated with DC Comics around 2001.)</li></ul><p><strong>Defunct</strong></p><ul><li><a href="/dcwildstorm/4015-58463/" data-ref-id="4015-58463">WildStorm</a> (1999-2010)* <ul><li><a href="/cmx/4015-58402/" data-ref-id="4015-58402">CMX</a> (2004-2010)</li><li><a href="/homage-comics/4015-58424/" data-ref-id="4015-58424">Homage Comics</a></li><li><a href="/cliffhanger/4015-58422/" data-ref-id="4015-58422">Cliffhanger</a></li><li><a href="/americas-best-comics/4015-58420/" data-ref-id="4015-58420">America''s Best Comics</a> (1999-2010)</li></ul></li><li><a href="/helix/4015-58388/" data-ref-id="4015-58388">Helix</a> (1996-1998)</li><li><a href="/tangent-comics/4015-58399/" data-ref-id="4015-58399">Tangent Comics</a> (1997-2008)</li><li><a href="/paradox-press/4015-58397/" data-ref-id="4015-58397">Paradox Press</a> (1993-2001)</li><li><a href="/piranha-press/4015-58392/" data-ref-id="4015-58392">Piranha Press</a> (1989-1994)</li><li><a href="/humanoids-dc-comics/4015-58419/" data-ref-id="4015-58419">Humanoids</a> (2004)</li><li><a href="/2000ad-dc-comics/4015-58521/" data-ref-id="4015-58521">2000AD</a> (Reprints from Rebellion''s <em>2000 AD</em> line)</li><li><a href="/milestone/4015-58336/" data-ref-id="4015-58336">Milestone</a> (Owned by Milestone Media)</li><li><a href="/impact-comics/4015-58443/" data-ref-id="4015-58443">Impact!</a></li><li><a href="/focus/4015-58404/" data-ref-id="4015-58404">Focus</a></li><li><a href="/minx/4015-58401/" data-ref-id="4015-58401">Minx</a> (2007-2008)</li><li><a href="/zuda-comics/4015-58410/" data-ref-id="4015-58410">Zuda</a> (2007-2010)</li><li><a href="/amalgam-comics/4015-58456/" data-ref-id="4015-58456">Amalgam Comics</a></li><li><a href="/dc-black-label/4015-57534/" data-ref-id="4015-57534">DC Black Label</a></li><li><a href="/elseworlds/4015-46699/" data-ref-id="4015-46699">Elseworlds</a></li><li><a href="/young-animal/4015-57103/" data-ref-id="4015-57103">Young Animal</a></li><li><a href="/jinxworld/4015-58520/" data-ref-id="4015-58520">Jinxworld</a></li></ul><p>*the imprint was founded in 1992 but as part of the <a href="/image/4010-513/" data-ref-id="4010-513">Image</a> conglomerate and only moved to DC in 1999.</p><h2>Other Media</h2><h4><strong>Film</strong></h4><p>DC Comics'' parent company Warner Brothers (with a few exceptions) has produced a variety of feature films based on DC Comics properties for cinematic release.</p><ul><li><em><a href="/superman-and-the-mole-men/4025-638/" data-ref-id="4025-638">Superman and the Mole-Men</a></em> (November 23, 1951)</li><li><em><a href="/batman-the-movie/4025-55/" data-ref-id="4025-55">Batman: The Movie</a></em> (July 30, 1966)</li><li><em><a href="/superman/4025-2/" data-ref-id="4025-2">Superman</a></em> (December 15, 1978)</li><li><em><a href="/superman-ii/4025-5/" data-ref-id="4025-5">Superman II</a> </em>(June 19, 1981)</li><li><em><a href="//www.comicvine.com/swamp-thin