INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, '<p>After Success with Collections of Popeye and Henry in 1935 David McKay published comics from 1936-1950. <a href="/ace-comics/4050-20975/" data-ref-id="4050-20975">Ace Comics </a>11 which contains the first appearance of The Phantom introduced one of the first of the costumed heroes.</p>', '14', 'David McKay', '[]', '[{"id": 776}, {"id": 806}, {"id": 11595}, {"id": 12110}, {"id": 20975}, {"id": 26978}, {"id": 28212}, {"id": 29967}, {"id": 31381}, {"id": 32691}, {"id": 36002}, {"id": 44111}, {"id": 44139}, {"id": 44232}, {"id": 46204}, {"id": 56850}, {"id": 73272}, {"id": 91074}, {"id": 142516}]', 'https://comicvine.gamespot.com/a/uploads/screen_medium/6/69951/3178876-784817.jpg');
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES ('American publisher, started in part by Will Eisner, and famous as the home of Plastic Man, Blackhawks, The Spirit and others.', '<p>Quality Comics went out of business in 1957 after having sold the rights to most of their characters to <a href="/dc-comics/4010-10/" data-ref-id="4010-10">DC Comics,</a> including <a href="/blackhawk/4005-35166/" data-ref-id="4005-35166">Blackhawk</a>, <a href="/darrell-dane/4005-23313/" data-ref-id="4005-23313">Doll Man</a>, <a href="/uncle-sam/4005-3625/" data-ref-id="4005-3625">Uncle Sam</a>, <a href="/human-bomb-lincoln/4005-47129/" data-ref-id="4005-47129">the Human Bomb</a>, the <a href="/black-condor-grey/4005-30198/" data-ref-id="4005-30198">Black Condor</a>, <a href="/phantom-lady-sandra-knight/4005-32175/" data-ref-id="4005-32175">Phantom Lady</a>, the <a href="/the-ray-happy-terrill/4005-47131/" data-ref-id="4005-47131">Ray</a>, <a href="/miss-america/4005-31887/" data-ref-id="4005-31887">Miss America</a>, the <a href="/dan-richards/4005-1333/" data-ref-id="4005-1333">Manhunter</a>, the <a href="/richard-raleigh/4005-47128/" data-ref-id="4005-47128">Red Bee</a>, <a href="/firebrand-rod-reilly/4005-76168/" data-ref-id="4005-76168">Firebrand</a>, <a href="/max-mercury/4005-2379/" data-ref-id="4005-2379">Max Mercury</a> (the Golden Age Quicksilver), <a href="/plastic-man/4005-6270/" data-ref-id="4005-6270">Plastic Man</a> and <a href="/the-spirit/4005-33297/" data-ref-id="4005-33297">the Spirit</a>. These characters continued to be published and updated by DC Comics.</p><p>Other characters from Quality Comics such as <a href="/midnight/4005-9554/" data-ref-id="4005-9554">Midnight</a>, <a href="/711/4005-53581/" data-ref-id="4005-53581">711</a>, <a href="/neon-the-unknown/4005-31889/" data-ref-id="4005-31889">Neon the Unknown</a>, the <a href="/red-torpedo/4005-62623/" data-ref-id="4005-62623">Red Torpedo</a> and the <a href="/the-invisible-hood/4005-31888/" data-ref-id="4005-31888">Invisible Hood</a> were also acquired by DC Comics. After a period of only a few appearances, these characters lapsed into limbo or into <a href="/in-the-public-domain/4010-2526/" data-ref-id="4010-2526">the public domain</a>.</p><p>Some of the original characters published by Quality Comics are:</p><p><a href="/711/4005-53581/" data-ref-id="4005-53581">711</a> (DC unpublished)</p><p><a href="/ace-of-space/4005-73860/" data-ref-id="4005-73860">Ace of Space</a></p><p><a href="/spider/4005-9978/" data-ref-id="4005-9978">Alias the Spider</a> (Quality, DC)</p><p>Amorpho</p><p>Archer</p><p><a href="/atmos-fear/4005-109509/" data-ref-id="4005-109509">Atmos Fear</a></p><p>Beauty</p><p>Bela Jet</p><p><a href="/big-shot/4005-76510/" data-ref-id="4005-76510">Big Shot</a> (Quality version)</p><p>Black Bat (Quality version)</p><p><a href="/black-condor-grey/4005-30198/" data-ref-id="4005-30198">Black Condor</a> (Quality, DC)</p><p>Black Death</p><p>Blackhawks (Quality, DC)</p><p>Blackout (Quality version) (Villain)</p><p>Black Shark</p><p>Blaze Barton</p><p><a href="/the-blue-tracer/4005-60021/" data-ref-id="4005-60021">Blue Tracer</a> (DC unpublished)</p><p><a href="/bozo-the-robot/4005-55419/" data-ref-id="4005-55419">Bozo the Iron Man</a> (The Robot)</p><p>Brain Master</p><p><a href="/brick-bat/4005-76533/" data-ref-id="4005-76533">Brick Bat</a></p><p><a href="/burp-the-twerp/4005-63892/" data-ref-id="4005-63892">Burp the Twerp</a></p><p><a href="/cadava/4005-81128/" data-ref-id="4005-81128">Cadava</a></p><p><a href="/captain-triumph/4005-36911/" data-ref-id="4005-36911">Captain Triumph</a> (Quality, DC)</p><p>Cobra (Quality version)</p><p><a href="/cobra-woman/4005-163819/" data-ref-id="4005-163819">Cobra Woman</a></p><p><a href="/commissioner-dolan/4005-26688/" data-ref-id="4005-26688">Commissioner Dolan</a> (Quality, DC, Dynamite)</p><p>Corpse</p><p>Corsair Queen</p><p>Crimesmith (Quality version)</p><p>Crossbow (Quality version)</p><p>Crystal Queen</p><p>Cyanide Cindy</p><p>Cyclone Space Pioneer</p><p><a href="/darling-oshea/4005-56214/" data-ref-id="4005-56214">Darling O'' Shea</a> (Quality, DC, Dynamite)</p><p>Death Patrol</p><p><a href="/destiny/4005-64082/" data-ref-id="4005-64082">Destiny</a> (Quality, DC) (Quality version)</p><p><a href="/destroying-demon/4005-76612/" data-ref-id="4005-76612">Destroying Demon</a></p><p>Doctor Claw</p><p><a href="/dr-cobra/4005-27734/" data-ref-id="4005-27734">Doctor Cobra</a> (Quality, DC, Dynamite)</p><p><a href="/darrell-dane/4005-23313/" data-ref-id="4005-23313">Doll Man</a> (Quality, DC)</p><p><a href="/doll-girl/4005-52970/" data-ref-id="4005-52970">Doll Girl</a> (Quality, DC)</p><p>Dr. Thirteen (Quality version)</p><p><a href="/dragon/4005-76613/" data-ref-id="4005-76613">Dragon</a></p><p>Espionage (<a href="/black-x/4005-1332/" data-ref-id="4005-1332">Black X</a>) (DC unpublished) (created by <a href="/will-eisner/4040-26686/" data-ref-id="4040-26686">Will Eisner</a>)</p><p><a href="/figure/4005-146714/" data-ref-id="4005-146714">Figure</a></p><p><a href="/firebrand-rod-reilly/4005-76168/" data-ref-id="4005-76168">Firebrand</a> (Quality, DC)</p><p><a href="/g-2/4005-135255/" data-ref-id="4005-135255">G-2</a></p><p>General Tala (Quality, Dell, Gold Key, Dynamite)</p><p><a href="/ghost-of-flanders/4005-70853/" data-ref-id="4005-70853">Ghost of Flanders</a></p><p>Granite Lady</p><p>Grasshopper</p><p>Great Defender</p><p>Green Lizard</p><p>Hand of Horror</p><p>Hazel P. Macbeth (Quality, DC. Dynamite)</p><p><a href="/her-highness/4005-69195/" data-ref-id="4005-69195">Her Highness</a> (Quality, DC)</p><p><a href="/human-bomb-lincoln/4005-47129/" data-ref-id="4005-47129">Human Bomb</a> (Quality, DC)</p><p>Huntress (Quality version)</p><p>Invisible Hood (Quality, DC)</p><p>Iron Emperor (Quality version)</p><p>Jane Arden (precursor to Lois Lane)</p><p><a href="/jester/4005-23433/" data-ref-id="4005-23433">Jester</a> (Quality, DC) (Hero)</p><p>Jester (Villain)</p><p>Jets</p><p><a href="/joe-hercules/4005-76774/" data-ref-id="4005-76774">Joe Hercules</a> (Quality, DC)</p><p><a href="/justnright/4005-75607/" data-ref-id="4005-75607">Just''n''Right</a></p><p><a href="/kid-eternity/4005-9363/" data-ref-id="4005-9363">Kid Eternity</a> (Quality, DC)</p><p>Kid Patrol</p><p><a href="/king-killer/4005-164819/" data-ref-id="4005-164819">King Killer</a></p><p><a href="/lady-luck/4050-26136/" data-ref-id="4050-26136">Lady Luck</a> (Quality, IDW, DC)</p><p>Laughing Puppeteer</p><p>Leopard Man (Quality version)</p><p>Lightning Man</p><p>Lorelie Rox (Quality, DC, Dynamite)</p><p>Madame Doom</p><p><a href="/madame-fatal/4005-41364/" data-ref-id="4005-41364">Madame Fatal</a> (Quality, DC)</p><p>Madame Serpina</p><p><a href="/magno/4005-66174/" data-ref-id="4005-66174">Magno</a> (Quality, DC)</p><p><a href="/manhunter/4005-2529/" data-ref-id="4005-2529">Manhunter</a> (Quality, DC)</p><p>Margo the Magician</p><p><a href="/marmaduke-mouse/4005-2758/" data-ref-id="4005-2758">Marmaduke the Mouse</a></p><p><a href="/marksman/4005-9560/" data-ref-id="4005-9560">Marksman</a> (Quality, DC)</p><p><a href="/master-man/4005-70137/" data-ref-id="4005-70137">Master Man</a> (Quality version)</p><p><a href="/merlin-the-magician/4005-124024/" data-ref-id="4005-124024">Merlin the Magician</a> (Quality, DC)</p><p>Midnight (Quality, DC)</p><p><a href="/miss-america/4005-31887/" data-ref-id="4005-31887">Miss America</a> (Quality, DC)</p><p><a href="/miss-fear/4005-72920/" data-ref-id="4005-72920">Miss Fear</a></p><p>Mister Carrion (Quality, DC, Dynamite)</p><p><a href="/molly-the-model/4005-63536/" data-ref-id="4005-63536">Molly the Model</a></p><p>Monsieur X</p><p><a href="/mouthpiece/4005-13166/" data-ref-id="4005-13166">Mouthpiece</a> (DC unpublished)</p><p><a href="/mr-aqua/4005-146706/" data-ref-id="4005-146706">Mr. Aqua</a></p><p><a href="/mr-green/4005-146724/" data-ref-id="4005-146724">Mr. Green</a></p><p><a href="/mr-keeper/4005-35415/" data-ref-id="4005-35415">Mr. Keeper</a> (Quality, DC)</p><p>Mr. Pointer</p><p><a href="/neon-the-unknown/4005-31889/" data-ref-id="4005-31889">Neon the Unknown</a> (Quality, DC)</p><p>Peg Leg Friel (DC unpublished)</p><p><a href="/pgell/4005-56213/" data-ref-id="4005-56213">P''Gell</a> (Quality, DC, Dynamite)</p><p><a href="/phantom-lady-sandra-knight/4005-32175/" data-ref-id="4005-32175">Phantom Lady</a> (Fox, Quality, DC)</p><p><a href="/plastic-man/4005-6270/" data-ref-id="4005-6270">Plastic Man</a> (Quality, DC)</p><p>Porcupine (Quality version)</p><p>Purple Shirts</p><p><a href="/max-mercury/4005-2379/" data-ref-id="4005-2379">Quicksilver</a> (Quality, DC) (Quality version)</p><p><a href="/raven/4005-145203/" data-ref-id="4005-145203">Raven</a> (DC unpublished) (Quality version)</p><p><a href="/the-ray-happy-terrill/4005-47131/" data-ref-id="4005-47131">The Ray</a> (Quality, DC)</p><p><a href="/richard-raleigh/4005-47128/" data-ref-id="4005-47128">Red Bee</a> (Quality, DC)</p><p><a href="/red-white-and-blue/4060-47327/" data-ref-id="4060-47327">Red, White, and Blue</a></p><p><a href="/red-torpedo/4005-62623/" data-ref-id="4005-62623">Red Torpedo</a> (Quality, DC)</p><p>Riverman</p><p><a href="/rusty-ryan/4005-75305/" data-ref-id="4005-75305">Rusty Ryan</a> (Quality, DC)</p><p><a href="/sadly-sadly/4005-164830/" data-ref-id="4005-164830">Sadly-Sadly</a></p><p><a href="/samar/4005-82258/" data-ref-id="4005-82258">Samar</a></p><p><a href="/sand-saref/4005-50044/" data-ref-id="4005-50044">Sand Saref</a> (Quality, DC, Dynamite)</p><p><a href="/scarlet-seal/4005-73803/" data-ref-id="4005-73803">Scarlet Seal</a> (Quality, DC)</p><p><a href="/silk/4005-69196/" data-ref-id="4005-69196">Silk</a> (Quality, DC)</p><p><a href="/satin/4005-30661/" data-ref-id="4005-30661">Silk Satin</a> (Quality, DC, Dynamite)</p><p><a href="/silken-floss/4005-30689/" data-ref-id="4005-30689">Silken Floss</a> (Quality, DC, Dynamite)</p><p><a href="/spider-widow/4005-53084/" data-ref-id="4005-53084">Spider Widow</a> (Quality, DC)</p><p>Steel Hand (Quality version)</p><p><a href="/steele-karrigan/4005-82668/" data-ref-id="4005-82668">Steele Karrigan</a></p><p>Strange Turns</p><p>Stretcho (Quality version)</p><p><a href="/stormy-foster/4005-76773/" data-ref-id="4005-76773">Stormy Foster</a> (Quality, DC)</p><p>Supermo</p><p>Suratai</p><p>Sword (Quality version)</p><p>The Barker (Quality, DC)</p><p><a href="/the-clock/4005-53494/" data-ref-id="4005-53494">The Clock</a> (Centaur, Quality, DC, Dynamite)</p><p><a href="/octopus/4005-28410/" data-ref-id="4005-28410">The Octopus</a> (Quality, DC, Dynamite)</p><p><a href="/the-sniper/4005-74499/" data-ref-id="4005-74499">The Sniper</a></p><p><a href="/the-spider/4005-146712/" data-ref-id="4005-146712">The Spider</a> (Quality version)</p><p><a href="/the-spirit/4005-33297/" data-ref-id="4005-33297">The Spirit</a> (Quality, Fiction House, Harvey, Dark Horse, DC, Dynamite)</p><p><a href="/the-unknown/4005-9563/" data-ref-id="4005-9563">The Unknown</a> (Quality, DC) (Quality version)</p><p>The Voice, Invisible Detective (Quality, Dell)</p><p>The War Wheel (Quality, DC) (Quality version)</p><p>The Whistler</p><p>The Whip (Quality version)</p><p>Thrilla</p><p>Tiger Woman</p><p><a href="/tom-thumb/4005-45738/" data-ref-id="4005-45738">Tom Thumb</a> (Quality version)</p><p><a href="/tor-the-magic-master/4005-127007/" data-ref-id="4005-127007">Tor</a> (Quality version)</p><p><a href="/torchy/4005-6646/" data-ref-id="4005-6646">T</a><a href="/torchy/4005-6646/" data-ref-id="4005-6646">orchy</a> (creator owned)</p><p><a href="/uncle-sam/4005-3625/" data-ref-id="4005-3625">Uncle Sam</a> (Quality, DC)</p><p><a href="/usa-the-spirit-of-old-glory/4005-52983/" data-ref-id="4005-52983">USA, the Spirit of Old Glory</a></p><p>Velvet</p><p>Wasp (Quality version)</p><p><a href="https://comicvine.gamespot.com/wildfire/4005-34303/" data-ref-id="4005-34303">Wildfire</a> (Quality, DC) (Quality version)</p><p><a href="/wings-wendall/4005-73804/" data-ref-id="4005-73804">Wings Wendall</a></p><p>Witch Quenn</p><p><a href="/wonder-boy/4005-61363/" data-ref-id="4005-61363">Wonder Boy</a> (DC unpublished) (Quality version)</p><p>Xaxol</p><p><a href="/x-of-the-underground/4005-77284/" data-ref-id="4005-77284">X of the Underground</a></p><p><a href="/x-5-secret-agent/4005-75929/" data-ref-id="4005-75929">X-5 Secret Agent</a> (changed to G-5 by DC)</p><p><a href="/yankee-eagle/4005-77282/" data-ref-id="4005-77282">Yankee Eagle</a></p><p><a href="/zero-ghost-detective/4005-82259/" data-ref-id="4005-82259">Zero: Ghost Detective</a> (Quality, Moonstone)</p><p><a href="/zorro/4005-15896/" data-ref-id="4005-15896">Zorro</a> (Quality, Dell, Gold Key, Dynamite)</p><p>DC published an <a href="/elseworlds/4015-46699/" data-ref-id="4015-46699">Elseworlds</a> title called <a href="/jla-destiny/4050-10771/" data-ref-id="4050-10771">JLA Destiny</a> where many of the Quality heroes founded the JLA and were funded by <a href="/thomas-wayne/4005-3602/" data-ref-id="4005-3602">Thomas Wayne</a>. The original members were The Clock, Manhunter, Midnight, and Destiny. The Unknown, Spider Widow, Wildfire, and Destiny were characters that were based on their 1940''s counter-parts. Joe Hercules and Stormy Foster appeared in Golden Age a DC Elseworlds title. Stormy would later make his New 52 debut in Earth 2. The Spirit was originally in newspapers that would later appear in <a href="/police-comics/4050-21167/" data-ref-id="4050-21167">Police Comics</a>. 711, Blue Tracer, Black X, Merlin the Magician, and Raven have not made any appearances in DC canon. Bozo the Robot, Madame Fatal, Mouthpiece, and Wonder Boy have only been referred to and Lady Luck is published by <a href="/idw-publishing/4010-1190/" data-ref-id="4010-1190">IDW publishing</a>. Lady Luck will make her DC appearance in Phantom Stranger 6. Stormy Foster and Torchy were the only characters that remained creator owned. Madame Fatale appeared in The Shade Mini series which was one of the few mini series published after The New 52.</p><p>Some of these characters have separate pages while others do not. There was a character named Mouthpiece in the 1999 Doctor Midnight mini series; it is unknown if he is related to the Quality character of the same name. Image Comics reimagned the Golden Age characters and published Crack Comics #63 as an anthology one shot around 2008. Most of the characters are owned by DC may have lapsed into the Public Domain. The characters story arcs that continued were The Mouthpiece, Molly the Model, Alias the Spider, Wildfire, and Captain Triumph.</p>', '15', 'Quality Comics', '[{"id": 56569}, {"id": 58196}, {"id": 59549}, {"id": 60614}, {"id": 60618}, {"id": 61057}, {"id": 62088}, {"id": 62089}]', '[{"id": 1248}, {"id": 1332}, {"id": 10729}, {"id": 10784}, {"id": 10831}, {"id": 10850}, {"id": 11655}, {"id": 12012}, {"id": 12038}, {"id": 18074}, {"id": 19487}, {"id": 19583}, {"id": 21050}, {"id": 21167}, {"id": 21864}, {"id": 22553}, {"id": 25537}, {"id": 25803}, {"id": 25913}, {"id": 25926}, {"id": 25975}, {"id": 26041}, {"id": 26136}, {"id": 26650}, {"id": 27516}, {"id": 28010}, {"id": 31318}, {"id": 31319}, {"id": 31709}, {"id": 32413}, {"id": 34000}, {"id": 34150}, {"id": 34151}, {"id": 34152}, {"id": 34153}, {"id": 34154}, {"id": 34155}, {"id": 34217}, {"id": 34218}, {"id": 34219}, {"id": 34245}, {"id": 42166}, {"id": 42317}, {"id": 50324}, {"id": 50351}, {"id": 51297}, {"id": 56005}, {"id": 57394}, {"id": 57415}, {"id": 58877}, {"id": 61741}, {"id": 62326}, {"id": 62646}, {"id": 72206}, {"id": 76309}, {"id": 142286}]', 'https://comicvine.gamespot.com/a/uploads/screen_medium/6/69951/1387458-logo_quality.jpg');
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, '<p><b>Fox Feature Syndicate</b> (also known as <b>Fox Comics</b> and <b>Fox Publications</b>) was an early comic book publisher in the <a href="/golden-age-of-comics/4015-55820/" data-ref-id="4015-55820">Golden Age of Comic Books</a>. Founded by entrepreneur <a href="//www.comicvine.com/victor-fox/4040-49436/" data-ref-id="4040-49436">Victor S. Fox</a>, it produced such popular titles as <a href="/the-blue-beetle/4050-19402/" data-ref-id="4050-19402">Blue Beetle</a>, <a href="/fantastic-comics/4050-19504/" data-ref-id="4050-19504">Fantastic Comics</a> and <a href="/mystery-men-comics/4050-20530/" data-ref-id="4050-20530">Mystery Men Comics</a>.</p><p>It is unrelated to the company Fox Publications, a Colorado publisher of railroad photography books.</p><p><a href="/victor-fox/4040-49436/" data-ref-id="4040-49436">Victor S. Fox </a> and business associate <a href="/bob-farrell/4040-137648/" data-ref-id="4040-137648">Bob Farrell</a> launched Fox Feature Syndicate at 480 Lexington Avenue in New York City in the late 1930s. For content, Fox contracted with comics packager <a href="/will-eisner/4040-26686/" data-ref-id="4040-26686">Eisner</a> &amp; <a href="/s-m-jerry-iger/4040-41635/" data-ref-id="4040-41635">Iger</a>, one of a handful of companies creating comic books on demand for publishers then entering the field. Writer-artist Will Eisner, at Victor Fox''s request for a hero similar to the newly published hit <a href="//www.comicvine.com/superman/4005-1807/" data-ref-id="4005-1807">Superman</a>, created the superhero <a href="/wonder-man/4005-73295/" data-ref-id="4005-73295">Wonder Man</a> for Fox''s first publication, <em><a href="/wonder-comics-1-the-wrath-of-allah/4000-233637/" data-ref-id="4000-233637">Wonder Comics #1</a></em> (May 1939), signing his work "Willis". Superman owner <a href="/national-periodical-publications/4010-24/" data-ref-id="4010-24">National Periodical Publications</a>, the company that would evolve into DC Comics, cited copyright infringement and quickly obtained a permanent injunction. Wonder Man did not reappear.</p><p>After Eisner testified against Fox Publications at trial, Victor Fox dropped the packager and hired his own stable of comic creators, beginning with a New York Times classified ad on Dec. 2, 1939. <a href="/joe-simon/4040-9443/" data-ref-id="4040-9443">Joe Simon</a>, a former Eisner &amp; Iger freelancer, became Fox Publications'' editor.</p><p>As one of the earliest companies in the emerging field, it employed or bought the packaged material of a huge number of Golden Age greats, many at the start of their careers. <a href="/lou-fine/4040-24756/" data-ref-id="4040-24756">Lou Fine</a> created the superhero <a href="/the-flame/4005-24757/" data-ref-id="4005-24757">The Flame</a> in <a href="/wonderworld-comics/4050-20532/" data-ref-id="4050-20532">Wonderworld Comics</a>; <a href="/dick-briefer/4040-43461/" data-ref-id="4040-43461">Dick Briefer</a> created <a href="/rex-dexter/4005-17833/" data-ref-id="4005-17833">Rex Dexter of Mars</a> in the eponymous series. <a href="/george-tuska/4040-9435/" data-ref-id="4040-9435">George Tuska</a> did his first comics work here with the features "Zanzibar" (<a href="/mystery-men-comics-1-the-case-of-tintypes-will-the/4000-122950/" data-ref-id="4000-122950"><em>Mystery Men Comics #1</em></a>, Aug. 1939) and "Tom Barry" (<a href="/wonderworld-comics-4-ambushing-the-smoky-hill-stag/4000-123263/" data-ref-id="4000-123263"><em>Wonderworld Comics #4</em></a>). <a href="/fletcher-hanks/4040-56582/" data-ref-id="4040-56582">Fletcher Hanks</a> created, wrote, and drew <a href="/stardust-the-super-wizard/4005-27007/" data-ref-id="4005-27007">Stardust the Super Wizard</a> in Fantastic Comics in 1939 and 1940. <a href="/matt-baker/4040-27899/" data-ref-id="4040-27899">Matt Baker</a>, one of the few African-American comic book artists of the Golden Age, revamped — in more than one sense — the newly acquired <a href="/quality-comics/4010-15/" data-ref-id="4010-15">Quality Comics</a> character <a href="/phantom-lady/4050-26918/" data-ref-id="4050-26918">Phantom Lady</a>'' in 1947, creating one of the most memorable and controversial examples of superhero "good girl art".</p><p>Future comics legend <a href="/jack-kirby/4040-5614/" data-ref-id="4040-5614">Jack Kirby</a>, brought on staff here after freelancing for Eisner &amp; Iger, wrote and drew the syndicated newspaper comic strip The Blue Beetle (starting Jan. 1940), starring a character created by <a href="/charles-nicholas/4040-39294/" data-ref-id="4040-39294">Charles Nicholas Wojtkowski</a> in <em>Mystery Men Comics #1</em> (Aug. 1939). Kirby retained the house name "Charles Nicholas" for the comic strip, which lasted three months. Kirby, additionally, created and did one story each of the Fox features "<a href="/wing-turner/4005-79866/" data-ref-id="4005-79866">Wing Turner</a>" (<a href="/mystery-men-comics-10/4000-122984/" data-ref-id="4000-122984"><em>Mystery Men #10</em></a>, May 1940) and " <a href="/cosmic-carson/4005-73810/" data-ref-id="4005-73810">Cosmic Carson</a>" (<a href="/science-comics-4/4000-197120/" data-ref-id="4000-197120"><em>Science Comics #4</em></a>, same month).</p><p>Throughout the 1940s, Fox produced comics in a typically wide variety of genres, but was best known for superheroes and humor. With the post-war decline in superheroes'' popularity, Fox, like other publishers, concentrated on horror and crime comics, including some of the most notorious of the latter. Following the establishment of <a href="/comics-code-authority/4015-42382/" data-ref-id="4015-42382">Comics Code Authority</a> in the mid-1950s, Fox went out of business, selling the rights to the Blue Beetle to <a href="/charlton/4010-125/" data-ref-id="4010-125">Charlton Comics</a>.</p><p>Born in England, Fox Publications founder Victor S. Fox was a stockbroker for the Allied Capital Corp./Fox Motor and Bank Stocks, Inc./American Common Stocks, Inc., on Park Avenue in New York City when he was [indicted citation needed] on Nov. 27, 1929 for mail fraud and related illegal "boiler room" activities. It appears unrecorded whether this resulted in a conviction.</p><p>Historian Jon Berk rumors that Fox went on to become an accountant/bookkeeper at the publishing firm that would become DC Comics, where he was privy to sales figures that convinced him to launch his own comic-book company. Fellow historian <a href="/gerard-jones/4040-41475/" data-ref-id="4040-41475">Gerard Jones</a>, writing in his book Men of Tomorrow: Geeks, Gangsters, and the Birth of the Comic Book, was unable to find documentation of this. Other sources say that at the time <em><a href="/action-comics-1-superman-champion-of-the-oppressed/4000-105403/" data-ref-id="4000-105403">Action Comics #1</a></em> came out he was publishing Astrology magazines and shared a distributor with DC after seeing a sales card receipt for Action #1 he Immediately opened Fox comics in the same building DC was based in on a different floor.</p><p><b>Jack Kirby</b>: "Victor Fox was a character. He''d look up at the ceiling with a big cigar, this little fellow, very broad, going back and forth with his hands behind his back saying, ''I''m the King of Comics! I''m the King of Comics!'' and we would watch him and, of course, smile a little because he was a genuine type".</p><p><a href="/joe-simon/4040-9443/" data-ref-id="4040-9443"><b>Joe Simon</b></a> on Victor Fox : "He was an accountant for DC Comics. He was doing the sales figures and he liked what he saw. So, he moved downstairs and started his own company.... I happened to get a job; I went over to Fox and became editor there, which was just an impossible job, because ... there were no artists, no writers, no editors, no letterers — nothing there. Everything came out of the Eisner and Iger shop. ... He was a very strange character. He had kind of a British accent; he was like 5''2", told us he was a former ballroom dancer. He was very loud, menacing, and really a scary little guy. He used to say, ''I''m the King of the Comics. I''m the King of the Comics. I''m the King of the Comics.'' We couldn''t stop him".</p><p><b>Nicky Wright</b>: "Competing well in the ''most sexy, sadistic, and violent'' category, Victor Fox’s Murder Incorporated and Blue Beetle are noteworthy.... When historians describe sleaze, sex, and violence as Fox’s obsession, they are masters of understatement. His best artists, Jack Kamen and Matt Baker, are much revered and collected for their good girl art. (Of special note is the company’s breasty crime-fighter-in-bedroom-lingerie, Phantom Lady...along with the wild and scantily attired Rulah, Jungle Goddess.)"</p><p><b>Boyd Magers</b>: "Never one to overlook a secondary sale, Fox often repackaged four remaindered (unsold) comics into a 25¢ Giant with a new cover, hence Hoot Gibson''s Western Roundup, 132 pages dated 1950. However, since Fox always started their stories on the inside front cover (where other publishers ran an ad), these repackaged comics are always missing the first page of story content. Also, since Fox used remaindered issues, contents will vary from copy to copy of Hoot Gibson''s Western Roundup."</p><p>Dynamite Entertainment has revived a few of the Fox Feature Syndicate characters in their Project Superpowers title</p><p>A portion of the stable of characters that were originally published by Fox are:</p><p>Ace of Spades</p><p>Adam Anteas, Jr.</p><p>Agent D-13</p><p>Ayesha</p><p><a href="/the-banshee/4005-73801/" data-ref-id="4005-73801">The Banshee</a></p><p>The Bat Boy</p><p>Beast (Fox version)</p><p>Beau Brummel</p><p>Betty Boyd</p><p>Bird Man (Fox version)</p><p>Black Baron (Fox version)</p><p>Blackbird (Fox version)</p><p>Black Death (Fox version)</p><p>Black Flagg</p><p><a href="/black-fury/4005-73806/" data-ref-id="4005-73806">Black Fury and Kid Fury</a> (Fox and Holyoke)</p><p>Black Fury II, Black Fury III</p><p>Black Lion and Cub</p><p>Black Rider</p><p>Black Snake</p><p>Black Tarantula</p><p>Blast Bennett</p><p>Blitz (Fox version)</p><p><a href="/blue-beetle-garret/4005-18745/" data-ref-id="4005-18745">Blue Beetle</a> and Sparky (Fox, Holyoke, Charlton, DC, Dynamite)</p><p><a href="/the-bouncer/4005-75003/" data-ref-id="4005-75003">The Bouncer</a></p><p>Bronze Man (Fox version)</p><p>Bwani</p><p>Captain Abbott</p><p>Captain Kidd</p><p>Captain Savage</p><p>Captain V</p><p>Captain X-13</p><p>Condor (Enemy of the original Blue Beetle)</p><p>Cosmic Carson (Created by Jack Kirby)</p><p>D-13 (Fox version)</p><p><a href="/dagar-desert-hawk/4005-34228/" data-ref-id="4005-34228">Dagar, the Desert Hawk</a></p><p><a href="/dart-ace/4060-57404/" data-ref-id="4060-57404">Dart and Ace</a>, the Amazing Boy (Fox, Dynamite)</p><p>Deathmask</p><p>Demon (Fox version)</p><p>Diana</p><p>Doctor Death (Fox version)</p><p>Doctor Drool</p><p>Doctor Fung</p><p>Doctor Mortal</p><p>Doctor Mortinous</p><p>Dr. Doom (Fox version)</p><p>The Dome (Fox version)</p><p>Doxol</p><p><a href="/dynamite-thor/4005-73824/" data-ref-id="4005-73824">Dynamite Thor</a></p><p>Dynamo (Fox version)</p><p>Echo (Fox version)</p><p><a href="/the-eagle/4005-18752/" data-ref-id="4005-18752">The Eagle and Buddy</a>, the Daredevil Boy (Fox, Dynamite)</p><p><a href="/dynamo/4005-20352/" data-ref-id="4005-20352">Electro ( later Dynamo)</a></p><p><a href="/the-flame/4005-24757/" data-ref-id="4005-24757">The Flame</a> and <a href="/flame-girl/4005-51189/" data-ref-id="4005-51189">Flame Girl </a>(Fox, Dynamite) (Will Eisner creations)</p><p>Flip Falcon</p><p>Gary Brent</p><p>Gimp</p><p>Gladiator</p><p>Gloat</p><p>Golden Knight</p><p>Gordon Fife and the Boy King</p><p>The Gorilla with the Human Brain</p><p><a href="/green-mask/4005-51185/" data-ref-id="4005-51185">Green Mask</a> and Domino (Fox, Dynamite)</p><p>Green Mask II</p><p>Halo (Fox, Holyoke)</p><p>The Hand (Fox version)</p><p>Hooded Master</p><p>Hooded Specter of Death</p><p>Hooded Terror</p><p>Illuso</p><p>Izzuki of Amazonland</p><p>Jaguar/Jaguar Man</p><p><a href="/jo-jo-congo-king/4050-19615/" data-ref-id="4050-19615">Jo Jo, the Congo King</a></p><p>Jungle Jo</p><p>Jungle Lil</p><p>K-5</p><p>Kalkor</p><p>Karno the Chessman</p><p>King Cobra</p><p>Krooga</p><p>Lantida of Atlantis</p><p>Lu-Nac</p><p>Lunar the Moon Man</p><p><a href="/the-lynx/4005-71660/" data-ref-id="4005-71660">The Lynx</a> and Blackie the Mystery Boy</p><p>Manx</p><p><a href="/panther-woman/4005-69423/" data-ref-id="4005-69423">Marga the Panther Woman</a></p><p>Martha of the Tree Folk</p><p>The Mask (Fox version)</p><p>Mastermind of Crime</p><p>Mea of Mermea</p><p>Merciless the Sorceress</p><p>Miss Green Mask</p><p>Miss X</p><p>Mokon, King of the Moon</p><p>Moth/Mothman</p><p>Moths</p><p>Mr. Death</p><p>Mystery Man</p><p>Nightbird</p><p>Navy Jones</p><p>Numa</p><p>Octopus (Fox version)</p><p>Perisphere Payne</p><p><a href="/phantom-lady/4050-26918/" data-ref-id="4050-26918">Phantom Lady</a> (Fox, Quality, later DC)</p><p>Phantom Rider (Fox version)</p><p>Phara</p><p>Prince Ferdinand Diablo</p><p>Professor Fiend</p><p>Puppeteer (Fox version)</p><p><a href="/purple-tigress/4005-61284/" data-ref-id="4005-61284">Purple Tigress</a></p><p>Queen Alice</p><p>Queen of Evil</p><p>Ragin Doctor</p><p>Rani-Boy</p><p>The Rapier</p><p>The Raven (Fox version)</p><p>Red Robbins</p><p>Rex Dexter of Mars</p><p>Robbing Robot</p><p>Rocket Kelly</p><p>Rook (Fox version)</p><p><a href="/rulah-jungle-goddess/4050-21051/" data-ref-id="4050-21051">Rulah, Jungle Goddess</a> (Fox, Ajax Farell)</p><p><a href="/samson/4005-52544/" data-ref-id="4005-52544">Samson</a> and David (Fox, Dynamite)</p><p>Saturina</p><p>The Scarecrow (Fox version)</p><p>Scorpion (Fox version)</p><p>Sea-Weed Men</p><p>Secret Agent D-13</p><p>Serpent Lady</p><p>Skull</p><p>Sorceress of Zoom</p><p>Space Smith</p><p>Sphinx</p><p><a href="/spider-queen/4005-30223/" data-ref-id="4005-30223">Spider Queen</a></p><p><a href="/stardust-the-super-wizard/4005-27007/" data-ref-id="4005-27007">Stardust, the Super Wizard</a></p><p>Sub Saunders</p><p>Sulia of Souless Isle</p><p>Sukon, King of the Sun</p><p>Super Spy Q-4</p><p>Swamp Master</p><p>Tanee</p><p><a href="/tangi/4005-2377/" data-ref-id="4005-2377">T</a><a href="/tangi/4005-2377/" data-ref-id="4005-2377">angi</a></p><p>Tegra, Jungle Empress</p><p>Thor (Fox version)</p><p>Thinker (Fox version)</p><p>The Topper</p><p>Tumbler</p><p>Typhon</p><p><a href="/us-jones/4005-17039/" data-ref-id="4005-17039">U.S. Jones</a> (Fox, Dynamite)</p><p><a href="/v-man/4005-8119/" data-ref-id="4005-8119">V-Man and the V-Boys</a> (Fox, Holyoke, Dynamite)</p><p>Voodoo Man</p><p>Weather Kings</p><p>Wing Turner (Created by Jack Kirby)</p><p>Winkon, King of the Winds</p><p><a href="/wonder-man/4005-73295/" data-ref-id="4005-73295">Wonder Man</a> (Fox version) (Created by Will Eisner)</p><p><a href="/the-wraith/4005-74160/" data-ref-id="4005-74160">The Wraith</a> (Fox version)</p><p>Yank and Rebel</p><p>Yank Wilson</p><p><a href="/yarko-the-great/4005-12801/" data-ref-id="4005-12801">Yarko, the Great</a></p><p>Zago, Jungle Prince</p><p>Zanzibar, The Magician</p><p>Zegra, Jungle Princess</p><p>Zoro, the Wizard</p><p>Many of these characters have their own separate page and others do not. <a href="/image/4010-513/" data-ref-id="4010-513">Image</a> reimagined Golden Age characters and literally published the next issue as an anthology one shot series in 2008. They published <a href="/fantastic-comics-24/4000-145597/" data-ref-id="4000-145597"><em>Fantastic Comics #24</em></a> on February 13 2008.</p><p>The issue republished the continuing story arc of characters Samson, Flip Falcon, Golden Knight, Yank Wilson, Space Smith, Captain KIdd, Professor Fiend, Sub Saunders, and Stardust the Super Wizard.</p>', '18', 'Fox Comics (US)', '[{"id": 58099}, {"id": 58634}, {"id": 58635}, {"id": 58636}, {"id": 58646}, {"id": 5865