"id": 133642}, {"id": 133643}, {"id": 140432}, {"id": 142644}, {"id": 145681}, {"id": 147023}, {"id": 149220}, {"id": 150417}, {"id": 156959}, {"id": 158013}, {"id": 158425}, {"id": 158520}, {"id": 158521}, {"id": 160188}]', 'https://comicvine.gamespot.com/a/uploads/screen_medium/1/15776/9060843-harveycomics.jpg');
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES ('Eastern Color Printing are given credit for the birth of the comic book. Funnies on Parade and Famous Funnies were the two comics that gave birth to the medium. Eastern Color published comics from 1933 through the mid 1950''s. In 1973 it ceased printing comics for other companies.', '<p>In the early 2000''s Eastern Color closed it''s doors.</p><p><a href="/dynamite-entertainment/4010-1859/" data-ref-id="4010-1859">Dynamite Entertainment</a> has recently revived some of these characters in the <a href="/project-superpowers/4050-20326/" data-ref-id="4050-20326">Project Superpowers</a> title.</p><p>This is list of a few of the stable of characters that were originally published by Easter Color Printing:</p><p>Buck Rogers novella Armageddon 2419 A.D. (Eastern Color, Toby, Dell, Gold Key, Marvel, DC, Dynamite)</p><p>Dan Dunn, the other Dick Tracy (Eastern Color, Dell, Gold Key)</p><p>Dr. Chuda</p><p>Fearless Flint ( Eastern Color, Dynamite)</p><p>Flash Gordon (Toby, Eastern Color, Dell. Gold Key, Harvey, Charlton, Mar, DC, DE)</p><p>Fly''n Jenny</p><p><a href="/hydroman/4005-59140/" data-ref-id="4005-59140">Hydroman</a> (Eastern Color, Dynamite)</p><p>Invisible Scarlet O''Neil (Eastern Color, Harvey)</p><p>Jane Arden (Eastern Color, Quality)</p><p>King Fiu</p><p>Lava Man</p><p>Lone Rider (Eastern Color, Ajax Farell)</p><p><a href="/man-o-metal/4005-18739/" data-ref-id="4005-18739">Man O'' Meta</a><a href="/man-o-metal/4005-18739/" data-ref-id="4005-18739">l</a> (Eastern Color, Dynamite)</p><p>Mann of India</p><p>Music Master</p><p><a href="/rainbow-boy/4005-60071/" data-ref-id="4005-60071">Rainbow Boy</a> (Eastern Color, Dynamite)</p><p>Spider Woman (Eastern Color version)</p><p><a href="/purple-zombie/4005-73942/" data-ref-id="4005-73942">T</a><a href="/purple-zombie/4005-73942/" data-ref-id="4005-73942">he Purple Zombie</a> (Eastern Color, Gold Key)</p><p>Third Key</p><p>Zina of Koraka</p><p>Many of these characters have separate pages and some do not.</p>', '22', 'Eastern Color', '[]', '[{"id": 794}, {"id": 10855}, {"id": 11230}, {"id": 11639}, {"id": 12080}, {"id": 19491}, {"id": 24680}, {"id": 24737}, {"id": 25366}, {"id": 26910}, {"id": 28055}, {"id": 30033}, {"id": 30035}, {"id": 30036}, {"id": 30046}, {"id": 30834}, {"id": 30835}, {"id": 32056}, {"id": 49068}, {"id": 56163}, {"id": 56848}, {"id": 58987}, {"id": 59874}, {"id": 60485}, {"id": 60510}, {"id": 60886}, {"id": 61104}, {"id": 61494}, {"id": 61602}, {"id": 61803}, {"id": 63402}, {"id": 63519}]', 'https://comicvine.gamespot.com/a/uploads/screen_medium/6/69951/1395337-famous_funnies.jpg');
