INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES ('Formerly known by names including "Atlas" and "Timely", Marvel Entertainment is the publisher of comic books featuring iconic characters and teams such as the Fantastic Four, Spider-Man, the Avengers, the X-Men, Iron Man, the Hulk, Thor, Captain America and Daredevil. Currently owned by the Walt Disney Company, Marvel is one of the "Big Two" comic publishers along with DC Comics.', '<h2>Origin</h2><p>Created by current co publisher of Marvel, <a href="https://comicvine.gamespot.com/stan-lee/4040-40467/" data-ref-id="4040-40467">Stan Lee</a>.</p><h2>Imprints</h2><ul><li><a href="https://www.comicvine.com/crossgen/4010-1099/" data-ref-id="4010-1099">Crossgen</a> (formerly independent)</li><li><a href="/epic/4015-58417/" data-ref-id="4015-58417">Epic</a> (Former)</li><li><a href="/icon-comics/4015-58414/" data-ref-id="4015-58414">Icon Comics</a></li><li><a href="https://www.comicvine.com/malibu/4010-447/" data-ref-id="4010-447">Malibu Comics</a> (formerly independent, acquired 1994)</li><li><a href="/marvel-digital-comics-unlimited/4010-2707/" data-ref-id="4010-2707">Marvel Digital Comics Unlimited</a></li><li><a href="/marvel-knights/4015-58406/" data-ref-id="4015-58406">Marvel Knights</a></li><li><a href="/marvel-music/4015-58391/" data-ref-id="4015-58391">Marvel Music</a></li><li><a href="/max-comics/4015-58411/" data-ref-id="4015-58411">MAX</a></li><li><a href="/barkerverse/4015-57852/" data-ref-id="4015-57852">Razorline</a> (Former)</li><li><a href="/marvel-soleil/4015-58418/" data-ref-id="4015-58418">Soleil</a></li><li><a href="/star-comics/4015-58457/" data-ref-id="4015-58457">Star Comics</a> (Former)</li><li>Ultimate Marvel</li></ul><h2>History</h2><p>In 1939 <a href="/martin-goodman/4040-43801/" data-ref-id="4040-43801">Martin Goodman</a> was persuaded by Frank Torpey, the sales manager of <a href="/funnies-inc/4010-1880/" data-ref-id="4010-1880">Funnies Inc.</a> to start publishing comics. This was the start of <a href="/timely/4010-21/" data-ref-id="4010-21">Timely Comics</a> Publications, which would later produce its first comic; <a href="/marvel-comics-1-marvel-comics/4000-109462/" data-ref-id="4000-109462"><i>Marvel Comics #1</i></a>.</p><h3><b>Timeline</b></h3><p><b>1936</b></p><ul><li>Introduction of <a href="/ka-zar/4005-3558/" data-ref-id="4005-3558"><i>Ka-Zar</i></a> in a pulp fiction magazine published by <a href="/manvis-publishing-company/4010-2888/" data-ref-id="4010-2888">Manvis</a> owned by <a href="/martin-goodman/4040-43801/" data-ref-id="4040-43801">Martin Goodman</a> prior to founding Timely Comics. <i>Ka-Zar</i> was created by Bob Byrd who was the author of <a href="/ka-zar-1-king-of-fang-and-claw/4000-186034/" data-ref-id="4000-186034"><i>Ka-Zar #1</i></a>. <i>Ka-Zar''s</i> pulp fiction story would later be adapted in <i>Marvel Comics #1</i>.</li></ul><p><b>1939</b></p><figure data-align="right" data-img-src="https://static.comicvine.com/uploads/original/5/54649/1045708-222_20060830001202_publisher_1_.jpg" data-ref-id="1300-1045708" data-size="medium" data-ratio="1.2" data-width="100" data-embed-type="image" style="width: 100px"><a class="fluid-height" style="padding-bottom:120.0%" href="https://static.comicvine.com/uploads/original/5/54649/1045708-222_20060830001202_publisher_1_.jpg" data-ref-id="1300-1045708"><img alt="The Timely logo" src="https://comicvine.gamespot.com/a/uploads/original/5/54649/1045708-222_20060830001202_publisher_1_.jpg" srcset="https://comicvine.gamespot.com/a/uploads/original/5/54649/1045708-222_20060830001202_publisher_1_.jpg 100w" sizes="(max-width: 100px) 100vw, 100px" data-width="100"></a><figcaption>The Timely logo</figcaption></figure><ul><li>Founding Timely Publications.</li><li><i>Marvel Comics #1</i>.</li><li>Introduction of <a href="/jim-hammond/4005-12605/" data-ref-id="4005-12605"><i>The Human Torch</i></a>.</li><li>Introduction of<a href="/namor/4005-1476/" data-ref-id="4005-1476"> <i>Sub-Mariner</i></a>.</li><li>Introduction of <a href="/ka-zar-rand/4005-79647/" data-ref-id="4005-79647"><i>Ka-Zar</i></a> in a comic book.</li><li>Introduction of <a href="/the-angel/4005-36389/" data-ref-id="4005-36389"><i>The Angel</i></a>.</li><li>Introduction of <a href="/masked-raider/4005-39664/" data-ref-id="4005-39664"><i>The Mask Raider</i></a>.</li><li><a href="/joe-simon/4040-9443/" data-ref-id="4040-9443">Joe Simon</a> is hired to be the first Editor and Chief of Timely.</li></ul><p><b>1940</b></p><ul><li>Artist <a href="/jack-kirby/4040-5614/" data-ref-id="4040-5614">Jack Kirby</a> joins Timely’s staff.</li></ul><ul><li>Goodman hired his wife’s teenage cousin, <a href="/stan-lee/4005-3115/" data-ref-id="4005-3115">Stanley Lieber</a>. He would later be known as <a href="https://comicvine.gamespot.com/stan-lee/4040-40467/" data-ref-id="4040-40467">Stan Lee</a>.</li><li>The “Marvel Universe” is created in when <a href="/namor/4005-1476/" data-ref-id="4005-1476">Namor</a> and <a href="/human-torch/4005-2120/" data-ref-id="4005-2120">The Human Torch</a> are in the first crossover issue.</li><li>Introduction of <a href="/thin-man/4005-35726/" data-ref-id="4005-35726"><i>The Thin Man</i></a>.</li><li>Introduction of <a href="/betty-dean/4005-36300/" data-ref-id="4005-36300"><i>Betty Dean</i></a>.</li><li>Introduction of <a href="/black-widow/4005-46234/" data-ref-id="4005-46234"><i>Black Widow</i></a>.</li><li>First “One off” <a href="/red-raven/4005-11367/" data-ref-id="4005-11367"><i>Red Raven</i></a> is introduced and the series doesn’t see a second issue.</li><li>The Roman gods <a href="/makkari/4005-13945/" data-ref-id="4005-13945">Mercury</a> and <a href="/kro/4005-11939/" data-ref-id="4005-11939">Pluto</a> made an appearance in <a href="/red-raven-comics-the-red-raven/4000-119368/" data-ref-id="4000-119368">Red Raven Comics #1</a> (Mercury in the 20th Century).</li><li><a href="/human-torch/4005-2120/" data-ref-id="4005-2120">The Human Torch</a> takes over the “Red Raven” series. Starting with <i><a href="/the-human-torch/4050-832/" data-ref-id="4050-832">The Human Torch</a> #2.</i> There was never a number 1.</li><li>Introduction of <a href="/toro/4005-11835/" data-ref-id="4005-11835">Toro</a>.</li><li>One story of <i>Super Hero Marvel Boy</i> was released.</li><li>Introduction of <i>Vision</i>.</li></ul><p><b>1941</b></p><ul><li>Introduction of <a href="/captain-america/4005-1442/" data-ref-id="4005-1442"><i>Captain America</i></a></li><li>Introduction of <a href="/bucky-barnes/4005-40470/" data-ref-id="4005-40470"><i>Bucky Barnes</i></a>.</li><li>Introduction of <a href="/the-patriot/4005-44588/" data-ref-id="4005-44588"><i>the</i> <i>Patriot</i></a>.</li><li>Timely comics fight the Nazis.</li><li>Introduction of the <a href="/red-skull/4005-2250/" data-ref-id="4005-2250"><i>Red Skull</i></a>.</li><li>Introduction of <a href="/blue-diamond/4005-22008/" data-ref-id="4005-22008"><i>Blue Diamond</i></a>.</li><li>Introduction of <a href="/the-fin/4005-13743/" data-ref-id="4005-13743"><i>the</i> <i>Fin</i></a>.</li><li><a href="https://comicvine.gamespot.com/stan-lee/4040-40467/" data-ref-id="4040-40467">Stanley Lieber</a> writes first story for Timely, <i>“<a href="/captain-america-comics/4050-1628/" data-ref-id="4050-1628">Captain America Comics</a> #4”,</i> under the pen name of <a href="https://comicvine.gamespot.com/stan-lee/4040-40467/" data-ref-id="4040-40467">Stan Lee</a>.</li><li>Teams <a href="/all-winners-squad/4060-44808/" data-ref-id="4060-44808">All Winners</a> and <a href="/young-allies/4060-40515/" data-ref-id="4060-40515">Young Allies</a> (formerly Sentinels of Liberty) make the first of Marvel’s many teams.</li><li>Introduction of <a href="/robert-frank/4005-14422/" data-ref-id="4005-14422"><i>The Whizzer</i></a>.</li><li>Introduction of <a href="/jack-frost/4005-35727/" data-ref-id="4005-35727"><i>Jack Frost</i></a>.</li><li><i>The Human Torch #5</i> depicts an epic battle between The Human Torch and Namor.</li><li>Introduction of <a href="/father-time/4005-46882/" data-ref-id="4005-46882"><i>Father Time</i></a>.</li><li>Introduction of <a href="/destroyer/4005-7942/" data-ref-id="4005-7942"><i>The Destroyer</i></a>.</li><li><a href="/joe-simon/4040-9443/" data-ref-id="4040-9443">Joe Simon</a> and <a href="/jack-kirby/4040-5614/" data-ref-id="4040-5614">Jack Kirby</a> leave Timely.</li><li><a href="https://comicvine.gamespot.com/stan-lee/4040-40467/" data-ref-id="4040-40467">Stan Lee</a> becomes Editor-in-Chief at the young age of 18 years old.</li></ul><p><b>1942</b></p><ul><li>The December 7 1941 attack on Pearl Harbor sends several Timely members into armed services.</li><li>Introduction of <a href="/citizen-v/4005-22669/" data-ref-id="4005-22669"><i>Citizen V</i></a>.</li><li>Introduction of <a href="/miss-fury/4005-51119/" data-ref-id="4005-51119"><i>Miss Fury</i></a>. (reprinted comic strips)</li><li>Introduction of <a href="/tessie-the-typist/4005-9375/" data-ref-id="4005-9375"><em>Tessie the Typist</em></a>.</li><li>Introduction of the funny animals <a href="/ziggy-pig/4005-55075/" data-ref-id="4005-55075">Ziggy Pig</a> and <a href="/silly-seal/4005-55076/" data-ref-id="4005-55076">Silly Seal</a>.</li><li><a href="/vincent-fago/4040-42206/" data-ref-id="4040-42206">Vince Fago</a> becomes Editor while <a href="https://comicvine.gamespot.com/stan-lee/4040-40467/" data-ref-id="4040-40467">Stan Lee</a> is off at war.</li></ul><p><b>1943</b></p><ul><li>Introduction of <a href="/super-rabbit/4050-32169/" data-ref-id="4050-32169"><i>Super Rabbit</i></a> to <a href="/comedy-comics/4050-944/" data-ref-id="4050-944">Comedy Comics</a>.</li><li>Introduction of <a href="/captain-wonder/4005-46390/" data-ref-id="4005-46390"><i>Captain Wonder</i></a>.</li><li><a href="/all-select-comics/4050-20016/" data-ref-id="4050-20016">All Select Comics</a> unite the big three, Captain , <a href="/namor/4005-1476/" data-ref-id="4005-1476">Sub-Mariner</a> and <a href="/jim-hammond/4005-12605/" data-ref-id="4005-12605">The Human Torch</a>.</li><li>Introduction of <i><a href="/miss-america/4005-13779/" data-ref-id="4005-13779">Miss America</a></i>.</li></ul><p><b>1944</b></p><ul><li>A<a href="//www.comicvine.com/captain-america/4005-1442/" data-ref-id="4005-1442"> Captain America</a> serial film was released as a 15 episode series.</li><li>Introduction of <a href="/patsy-walker/4005-3316/" data-ref-id="4005-3316"><i>Patsy Walker</i></a>.</li></ul><p><b>1945</b></p><ul><li>The end of World War 2 brought the decline of “Super Heroes” sales.</li><li>Introduction of <a href="/millie-the-model/4005-18526/" data-ref-id="4005-18526"><i>Millie the Model</i></a> who spawned 207 issues.</li><li>Introduction of <a href="/nellie-the-nurse/4005-5585/" data-ref-id="4005-5585"><i>Nellie the Nurse</i></a>.</li><li>Marvel reaches out to a young female audience.</li><li><a href="https://comicvine.gamespot.com/stan-lee/4040-40467/" data-ref-id="4040-40467">Stan Lee</a> returns to his chair as Editor-in-Chief after the war.</li></ul><p><b>1946</b></p><ul><li>Introduction of <a href="/blonde-phantom/4005-41880/" data-ref-id="4005-41880"><i>The Blonde Phantom</i></a>.</li><li>Introduction of <a href="/mighty-mouse/4005-39433/" data-ref-id="4005-39433"><i>Mighty Mouse</i></a>.</li><li><em>Young Allies Comics</em> was canceled.</li><li><em>All Winners Squad #21</em> was the last issue for the team.</li><li><a href="/harvey-kurtzman/4040-3909/" data-ref-id="4040-3909">Harvey Kurtzman</a> starts doing freelance work for Timely comics. He would later become the original editor of <i>MAD</i> magazine.</li><li><a href="/gene-colan/4040-3792/" data-ref-id="4040-3792">Gene Colan</a> is hired as an artist for Timely.</li></ul><p><b>1947</b></p><ul><li>Introduction to <a href="/namora/4005-2177/" data-ref-id="4005-2177"><i>Namora</i></a>.</li><li>As Super Hero comic stayed in a slump, Crime, <a href="/romance/4015-56132/" data-ref-id="4015-56132">Romance</a> and <a href="https://comicvine.gamespot.com/western/4015-56096/" data-ref-id="4015-56096">Westerns</a> gain in popularity.</li></ul><p><b>1948</b></p><ul><li><i>Comic Crime-fighters and <a href="/lawbreakers-always-lose/4050-1202/" data-ref-id="4050-1202">Lawbreakers Always Lose!</a></i> debut to increase the popularity of the crime comics.</li><li>Introduction of <a href="/clay-harder/4005-88519/" data-ref-id="4005-88519"><i>Two-Gun Kid</i></a>.</li><li>Introduction of <a href="/sun-girl/4005-36454/" data-ref-id="4005-36454"><i>Sun Girl</i></a>.</li><li>Introduction of <a href="/kid-colt/4005-7238/" data-ref-id="4005-7238"><i>Kid Colt</i></a>.</li><li>Introduction of <a href="/aphrodite-ourania/4005-178174/" data-ref-id="4005-178174"><i>Venus</i></a></li><li>Introduction of <em><a href="/black-rider/4005-32547/" data-ref-id="4005-32547">Black Rider</a></em>.</li><li><a href="/john-buscema/4040-3800/" data-ref-id="4040-3800">John Buscema</a> answers an ad to become one of the best know artists in Marvel’s history.</li><li>As Super Hero comics stayed in a slump, Crime, Romance and Westerns gain in popularity.</li></ul><p><b>1950''s</b></p><ul><li>Timely goes through an identity change. From Timely to Atlas Comics to eventually Marvel.</li></ul><p><b>1960''s</b></p><figure data-align="right" data-img-src="https://static.comicvine.com/uploads/original/0/4/5106-2045-5558-1-fantastic-four.jpg" data-ref-id="1300-5106" data-size="medium" data-ratio="1.5125" data-width="400" data-embed-type="image" style="width: 400px"><a class="fluid-height" style="padding-bottom:151.3%" href="https://static.comicvine.com/uploads/original/0/4/5106-2045-5558-1-fantastic-four.jpg" data-ref-id="1300-5106"><img alt="Fantastic Four #1 launches the "></a><figcaption>Fantastic Four #1 launches the "Marvel Age of Comics".</figcaption></figure><ul><li>As super hero comics make a re-emergence Marvel comes out with it''s new heroes. These heroes have more personal and emotional back stories</li><li>1961 sees the creation of <a href="/fantastic-four/4060-3804/" data-ref-id="4060-3804">The Fantastic Four</a>.</li><li>In the following years (following the successful relaunch of DC''s heroes ) Marvel launches the <a href="/hulk/4005-2267/" data-ref-id="4005-2267">Hulk</a>, <a href="/x-men/4060-3173/" data-ref-id="4060-3173">X-Men</a>, <a href="/iron-man/4005-1455/" data-ref-id="4005-1455">Iron Man</a>, <a href="/spider-man/4005-1443/" data-ref-id="4005-1443">Spider-Man</a>, <a href="/daredevil/4005-24694/" data-ref-id="4005-24694">Daredevil</a>, <a href="/avengers/4060-3806/" data-ref-id="4060-3806">Avengers</a>, The return of the Golden Age Captain America and many more.</li></ul><p>The comic-book arm of the company started in 1939 as <a href="/timely/4010-21/" data-ref-id="4010-21">Timely Publications</a>, and by the 1950s was generally known as <u>Atlas Comics</u>. Marvel''s modern incarnation dates from 1961, with the launching of <a href="/fantastic-four/4060-3804/" data-ref-id="4060-3804"><i>Fantastic Four</i></a> and other superhero titles created by <a href="https://comicvine.gamespot.com/stan-lee/4040-40467/" data-ref-id="4040-40467">Stan Lee</a>, Jack Kirby, Steve Ditko, and others. Marvel has since become the largest American comic book publisher over long time competitor <a href="/dc-comics/4010-10/" data-ref-id="4010-10">DC Comics</a>.</p><p><strong>Editors-in-chief</strong></p><ul><li><a href="/joe-simon/4040-9443/" data-ref-id="4040-9443">Joe Simon</a> (1940-1941)</li><li><a href="https://comicvine.gamespot.com/stan-lee/4040-40467/" data-ref-id="4040-40467">Stan Lee</a> (1941-1942)</li><li>Vincent Fago (acting editor during Lee''s military service) (1942-1945)</li><li><a href="https://comicvine.gamespot.com/stan-lee/4040-40467/" data-ref-id="4040-40467">Stan Lee</a> (1945-1972)</li><li><a href="/roy-thomas/4040-42067/" data-ref-id="4040-42067">Roy Thomas</a> (1972-1974)</li><li><a href="/len-wein/4040-41457/" data-ref-id="4040-41457">Len Wein</a> (1974-1975)</li><li><a href="/marv-wolfman/4040-41478/" data-ref-id="4040-41478">Marv Wolfman</a> (<u>black-and-white</u> magazines 1974-1975, entire line 1975-1976)</li><li><a href="/gerry-conway/4040-40871/" data-ref-id="4040-40871">Gerry Conway</a> (1976)</li><li><a href="/archie-goodwin/4040-42923/" data-ref-id="4040-42923">Archie Goodwin</a> (1976-1978)</li><li><a href="/jim-shooter/4040-40450/" data-ref-id="4040-40450">Jim Shooter</a> (1978-1987)</li><li><a href="/tom-defalco/4040-41037/" data-ref-id="4040-41037">Tom DeFalco</a> (1987-1994)</li><li><a href="/bob-harras/4040-40985/" data-ref-id="4040-40985">Bob Harras</a> (1995-2000)</li><li><a href="/joe-quesada/4040-1537/" data-ref-id="4040-1537">Joe Quesada</a> (2000-2011)</li><li><a href="/axel-alonso/4040-23115/" data-ref-id="4040-23115">Axel Alonso</a> (2011-Present)</li></ul><h2>Events in the Marvel Universe</h2><h3>1980''s</h3><ul><li><p><a href="https://comicvine.gamespot.com/marvel-super-hero-contest-of-champions/4050-3147/">Marvel Super Hero Contest of Champions </a>(1982)</p></li><li><p><a href="https://comicvine.gamespot.com/marvel-super-heroes-secret-wars/4050-3352/">Marvel Super Heroes Secret Wars </a>(1984-1985)</p></li><li><p><a href="https://comicvine.gamespot.com/secret-wars-ii/4050-3506/">Secret Wars II </a>(1985)</p></li></ul><h3>1990''s</h3><ul><li><a href="/infinity-gauntlet/4045-42233/" data-ref-id="4045-42233">The Infinity Gauntlet</a> (1991) - Collected In <a href="/infinity-gauntlet/4050-30365/" data-ref-id="4050-30365">Trade</a></li><li><a href="/operation-galactic-storm/4045-27758/" data-ref-id="4045-27758">Operation: Galactic Storm</a> (1992) - Collected In 2 Trades (<a href="/operation-galactic-storm-vol-1/4000-278054/" data-ref-id="4000-278054">1</a>, <a href="/operation-galactic-storm-vol-2/4000-278056/" data-ref-id="4000-278056">2</a>)</li><li><a href="/infinity-war/4045-42234/" data-ref-id="4045-42234">Infinity War</a> (1992) - Collected In <a href="/infinity-war/4050-30366/" data-ref-id="4050-30366">Trade</a></li><li><a href="/x-cutioners-song/4045-42178/" data-ref-id="4045-42178">X-Cutioner''s Song</a> (1992-1993) - Collected In Trade</li><li><a href="/infinity-crusade/4045-42235/" data-ref-id="4045-42235">Infinity Crusade</a> (1993) - Collected In 2 Trades (<a href="/infinity-crusade-volume-1/4000-187175/" data-ref-id="4000-187175">1</a>, <a href="/infinity-crusade-volume-2/4000-187188/" data-ref-id="4000-187188">2</a>)</li><li><a href="/maximum-carnage/4045-41409/" data-ref-id="4045-41409">Maximum Carnage</a> (1993) - Collected In <a href="/spider-man-maximum-carnage/4050-38267/" data-ref-id="4050-38267">Trade</a></li><li><a href="/fatal-attractions/4045-41878/" data-ref-id="4045-41878">Fatal Attractions</a> (1993) - Collected In <a href="/x-men-fatal-attractions/4050-31800/" data-ref-id="4050-31800">Trade</a></li><li><a href="/phalanx-covenant/4045-42176/" data-ref-id="4045-42176">Phalanx Covenant</a> (1994) - Collected In <a href="/origin-of-generation-x/4050-22011/" data-ref-id="4050-22011">Trade</a></li><li><a href="/clone-saga/4045-43775/" data-ref-id="4045-43775">Clone Saga</a> (1994-1996) - Collected In 5 Trades (<a href="/spider-man-the-complete-clone-saga-epic-book-one/4000-209111/" data-ref-id="4000-209111">1</a>, <a href="/spider-man-the-complete-clone-saga-epic-book-two/4000-216449/" data-ref-id="4000-216449">2</a>, <a href="/spider-man-the-complete-clone-saga-epic-book-three/4000-232983/" data-ref-id="4000-232983">3</a>, <a href="/spider-man-the-complete-clone-saga-epic-book-four/4000-246605/" data-ref-id="4000-246605">4</a>, <a href="/spider-man-the-complete-clone-saga-epic-book-five/4000-260054/" data-ref-id="4000-260054">5</a>)</li><li><a href="/age-of-apocalypse/4045-40752/" data-ref-id="4045-40752">Age of Apocalypse</a> (1995) - Collected In 4 Trades (<a href="/x-men-age-of-apocalypse-the-complete-epic-book-1/4000-191690/" data-ref-id="4000-191690">1</a>, <a href="/x-men-age-of-apocalypse-the-complete-epic-book-