INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES ('Ace Magazines was a Golden Age comic book publisher', '<p>The stable of characters of Ace Magazines were</p><p>Ace McCoy</p><p>Agent Q-13</p><p>The Black Ace</p><p>Black Puma</p><p>Black Spider (Ace Magazines version)</p><p>Blitz Buster</p><p>Blue Rubber Man</p><p>Blue Spark</p><p>Buck Steele</p><p>Buckskin Blake</p><p>The Clown (Ace Magazines version, Dynamite) (Clown C.E.O.)</p><p>Captain Courageous (Ace Magazines, Dynamite)</p><p>Captain Gallant (Ace Magazines version)</p><p>Captain Nippo (Ace Magazines, Dynamite)</p><p>Captain Victory (Ace Magazines version)</p><p>Congo Jack</p><p>Copperheads</p><p>Corporal Flint</p><p>Cougar (Ace Magazines version)</p><p>Cross Draw Kid</p><p>Dictator''s Shadow</p><p>Dr. Diablo</p><p>Dr. Nemesis (Ace Magazines, Marvel)</p><p>Doctor Oxyo</p><p>Eel (Ace Magazines version)</p><p>Fate (Ace Magazines version)</p><p>The Flag (Ace Magazines, Dynamite)</p><p>Flash Lightning</p><p>Gilda</p><p>Green Arrowhead</p><p>Green Genie</p><p>Hap Hazard</p><p>Icicle (Ace Magazines version)</p><p>Jewel</p><p>Lash Lightning and Lightning Girl (Ace Magazines, Dynamite)</p><p>Lenore Black</p><p>Lizard (Ace Magazines version-similar look to Marvel''s Lizard)</p><p>Lone Warrior and Dickey</p><p>Maestro (Ace Magazines version)</p><p>Magno the Magnetic Man and Davey (Ace Magazines, Dynamite)</p><p>Marvo the Magician</p><p>Mastermind (Ace Magazines version)</p><p>Mirror Man (Ace Magazines version)</p><p>Moon Man (Ace Magazines, Moonstone)</p><p>Mr. Risk</p><p>Old Man of the Pyramids</p><p>Paul Revere, Jr.</p><p>Phoenix (Ace Magazines version)</p><p>Professor Aries, the Invisible Man</p><p>Professor Bixby</p><p>Professor Octopus</p><p>Purple Plague</p><p>Red Death</p><p>Retribution</p><p>Secret Agent X, the Man of 1,000 Faces</p><p>Shinto Samaraui</p><p>Surgeon</p><p>Teacher</p><p>The Cobra (Ace Magazines, Dynamite)</p><p>The Mummy</p><p>The Raven (Mr. Raven) (Ace Magazines, Dynamite)</p><p>The Swami</p><p>The Sword and Lancer (Ace Magazines, Dynamite)</p><p>The Torcher</p><p>The Unknown</p><p>The Unknown Soldier (The Soldier Unknown) (Ace Magazines, Dynamite)</p><p>The Vulture (Ace Magazines version)</p><p>Tiger Man (Ace Magazines version)</p><p>Uno</p><p>Vulcan (Ace Magazines version, Dynamite)</p><p>Whiz Wilson</p><p>X-2</p><p>X the Phantom Fed (Ace Magazines, Moonstone)</p><p> </p><p> </p>', '32', 'Ace Magazines', '[{"id": 56419}, {"id": 56420}, {"id": 58121}, {"id": 58122}, {"id": 66418}]', '[{"id": 836}, {"id": 893}, {"id": 9326}, {"id": 10839}, {"id": 11445}, {"id": 11557}, {"id": 20090}, {"id": 20194}, {"id": 20669}, {"id": 20670}, {"id": 26311}, {"id": 32020}, {"id": 32511}, {"id": 34590}, {"id": 38268}, {"id": 39288}, {"id": 40505}, {"id": 40506}, {"id": 42789}, {"id": 46705}, {"id": 48472}, {"id": 49370}, {"id": 49371}, {"id": 49372}, {"id": 49373}, {"id": 49374}, {"id": 49375}, {"id": 49376}, {"id": 49377}, {"id": 49378}, {"id": 49379}, {"id": 49380}, {"id": 49381}, {"id": 49382}, {"id": 49383}, {"id": 49384}, {"id": 49385}, {"id": 49386}, {"id": 49396}, {"id": 49400}, {"id": 49401}, {"id": 49402}, {"id": 49403}, {"id": 49404}, {"id": 49418}, {"id": 49419}, {"id": 49420}, {"id": 49421}]', 'https://comicvine.gamespot.com/a/uploads/screen_medium/6/69951/1387443-logo_ace1.jpg');
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES ('Fawcett is best known as being the publisher that created Captain Marvel, who eclipsed Superman in sales during the Golden age. Eventually sued and forced out of business by litigious competitor DC, they ceased publishing in the early 1950s. 
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, '<p>Hillman Published Various titles chief among them were <a href="/air-fighters-comics/4050-18931/" data-ref-id="4050-18931">Air Fighters</a> and <a href="/airboy/4005-1432/" data-ref-id="4005-1432">Airboy.</a></p><p>A few of the Hillman characters have been revived by <a href="/">Dynamite Entertainment</a> under their <a href="/project-superpowers/4050-20326/" data-ref-id="4050-20326">Project Superpowers</a> title.</p><p>These are some of the stable of characters that were originally published by Hillman:</p><p><a href="/">Airboy</a> (Hillman, Moonstone, Image)</p><p><a href="/">The Heap</a> (Hillman, Moonstone)</p><p><a href="/">Skywolf</a> (Hillman, Moonstone)</p><p><a href="/">Valkyrie</a> (Hillman, Moonstone)</p><p><a href="/">Iron Ace</a> (Hillman, Moonstone)</p><p>Iron Lady (create by Simon-Kirby)</p><p><a href="/">Bald Eagle</a> (Hillman, Moonstone)</p><p>Airmaidens</p><p>Baroness Blood</p><p>Bill Colt, the Ghost Rider</p><p>Black Ace</p><p>Black Baron</p><p>Black Commander/Commander X (Hillman, Moonstone)</p><p>Black Mail</p><p><a href="/">Boy King</a> and his <a href="/giant/4005-18738/" data-ref-id="4005-18738">Giant</a> (Hillman, Dynamite)</p><p><a href="/">Black Angel</a></p><p>Blanda, Jungle Queen</p><p>Bomber Burns</p><p>Boy Rangers and Loco</p><p>Brother Crane</p><p>Bullet Bob</p><p>Buzzard Barnes and the Sky Devils</p><p>Checker</p><p>Conqueror</p><p>Crash Davis</p><p>Crusader, Man in Black</p><p>Dash Dixon, Man of Might</p><p>Deathless Brain</p><p>Defender, Man of 1,000 Faces</p><p>Dr. Plasma</p><p>Dr. Roulette</p><p>Dr. Royce</p><p>Dusty Doyle</p><p>Firebug (Hillman version)</p><p>Flying Cadet</p><p><a href="/">Flying Dutchman</a> (Hillman, Moonstone)</p><p>Flying Fool (Hillman, Moonstone) (created by Simon/Kirby)</p><p>Green Eyed Man</p><p>Gunmaster (Hillman version)</p><p>Half Man</p><p>Hitler''s Rex</p><p>K-7, Secret Agent</p><p>Lefty Larson</p><p>Madame Claw</p><p>Masked Angel</p><p>Micro-Face</p><p>Misery</p><p>Mosquito</p><p>Muggsy</p><p><a href="/">Nightmare</a> and <a href="/">Sleepy</a></p><p>Paris</p><p>Phantom Ranger</p><p>The Porcupine (Hillman version)</p><p>Punch and Judy (Hillman version)</p><p>Queen of Hearts</p><p>Rackman</p><p>Red Roberts, The Electro Man</p><p>Rocket Riley</p><p>Rubberman</p><p><a href="/">Sky Wizard</a>, Master of Space (Hillman, Dynamite)</p><p>Spade of the Secret Service</p><p>The Steel Shark (Hero)</p><p>The Steel Shark (Villian)</p><p>The Scorpion (Hillman version)</p><p>The Veiled Prophet</p><p>Tex Trainor</p><p><a href="/twilight/4005-32609/" data-ref-id="4005-32609">Twilight</a></p><p>Zippo</p><p>Zzed</p><p>Many of these characters have separate pages while others do not.</p>', '37', 'Hillman', '[{"id": 58162}, {"id": 58163}, {"id": 62718}, {"id": 66888}]', '[{"id": 1069}, {"id": 10737}, {"id": 11522}, {"id": 11540}, {"id": 18931}, {"id": 26221}, {"id": 26222}, {"id": 26812}, {"id": 29410}, {"id": 29425}, {"id": 32516}, {"id": 36447}, {"id": 36485}, {"id": 42914}, {"id": 57412}, {"id": 58256}, {"id": 58285}, {"id": 63033}, {"id": 63762}, {"id": 67160}, {"id": 70970}, {"id": 71262}, {"id": 74375}, {"id": 74376}, {"id": 143697}]', 'https://comicvine.gamespot.com/a/uploads/screen_medium/7/70215/9491196-hillman.jpg');
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES ('Prize Comics or Crestwood Publications was a Golden Age comic publisher from 1940 to 1968.
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES ('Founded in 1855, Street &amp; Smith was a New York publisher of inexpensive paperbacks and magazines called pulp fiction or dime novels, as well as comic books and sporting yearbooks.', '<p><i>sFrancis Scott Street and Francis Shubael Smith began their publishing partnership when they bought an old fiction magazine. In 1858 they bought the New York Weekly Dispatch, in 1933 they bought some tittles from Clayton Magazine which included "Astonishing Stories". In 1937 Street &amp; Smith discontinued many of their pulp tittles such as "Complete Stories" and "Top-Notch".</i></p><p>Street &amp; Smith stopped publishing pulps and comics in 1949 when sales declined due to the advent of television. They sold many of their tittles to <a href="/popular-publications/4010-3783/" data-ref-id="4010-3783">Popular Publications</a>. Conde Nast Publications bought them out in 1959. The company name continued to be used on the sports pre-season magazine until 2007. American City Business Journals acquired the Sporting News and merged Street and Smith in to TSN''s annuals.</p><p>Street &amp; Smith were responsible for creating such classic pulp characters as <a href="/the-shadow/4005-28923/" data-ref-id="4005-28923">The Shadow</a>, <a href="/the-avenger/4005-51424/" data-ref-id="4005-51424">The Avenger</a>, Justice Inc, and Doc Savage.</p><p>The other characters originally published by Street and Smith were</p><p>Ajax, The Sun Man</p><p>Bill Barnes</p><p>Black Dragon</p><p>The Black Fury V</p><p>Cap Fury</p><p>Crime Wizard</p><p>Dazaar, the Arch Fiend</p><p>Devil Kyoti</p><p>Doc Savage (Street and Smith, Gold Key, Marvel, DC, Dark Horse, Dynamite)</p><p>Dr. Quartz</p><p>Frank Merriwell</p><p>Frank Reed</p><p>Gadget Man (first creation of Lester Dent. This lead to the Dent''s creation of The Shadow)</p><p>Hooded Wasp with sidekicks Wasplet and Honey Wasp</p><p>Iron Ghost</p><p>Iron Munro, the Astonishing Man (Street and Smith version)</p><p>I. V. Frost (Street and Smith, Moonstone)</p><p>John Sunlight (Street and Smith, DC, Dynamite)</p><p>The Joker (Detective Story Magazine 1919)</p><p>Justice, Inc (Street and Smith, DC, Dynamite)</p><p>Metal Master (Street and Smith, Marvel)</p><p>Monstradamus (First multi-arc Shadow villian)</p><p>Nick Carter</p><p>Norgil the Magician</p><p>Professor Solarus, The Space Master</p><p>Red Dragon (Street and Smith version)</p><p>The Avenger (Street and Smith, DC, Dynamite)</p><p>The Shadow (Street and Smith, DC, Marvel, Dark Horse, Dynamite)</p><p>Shiwan Khan (Street and Smith, DC, Dynamite)</p><p>Spider (Street and Smith version)</p><p>The Talon</p><p>Thunderbolt (Street and Smith version)</p><p>Vanisher (Street and Smith, Marvel)</p><p>Voodoo Master (Street and Smith, Dynamite)</p><p>White Rook</p><p><a href="/dynamite-entertainment/4010-1859/" data-ref-id="4010-1859">Dynamite</a> publishes <a href="/the-shadow/4050-48063/" data-ref-id="4050-48063">The Shadow</a>. Shadow was published by DC. DC was publishing The Avenger, Doc Savage, and Justice Inc. before Dynamite picked up the publishing rights to all the characters.</p><p>Street &amp; Smith was purchased by Conde Nast in 1959.</p><p>Major series:</p><ul><li><a href="/shadow-comics/4050-26234/" data-ref-id="4050-26234">Shadow Comics</a> (1940)</li><li><a href="/doc-savage-comics/4050-26235/" data-ref-id="4050-26235">Doc Savage Comics</a> (1940)</li><li><a href="/super-magician-comics/4050-26233/" data-ref-id="4050-26233">Super-Magician Comics</a> (1941)</li><li><a href="/supersnipe-comics/4050-25828/" data-ref-id="4050-25828">Supersnipe Comics</a> (1942)</li><li><a href="/air-ace/4050-34365/" data-ref-id="4050-34365">Air Ace</a> (1944)</li></ul><p>For a list of Street and Smith publications including the pulp work see <a href="http://en.wikipedia.org/wiki/List_of_Street_%26_Smith_publications" rel="nofollow ">Wikipedia.org</a>.</p>', '46', 'Street and Smith', '[{"id": 56516}, {"id": 57571}]', '[{"id": 10814}, {"id": 11547}, {"id": 11548}, {"id": 25828}, {"id": 26233}, {"id": 26234}, {"id": 26235}, {"id": 26239}, {"id": 26243}, {"id": 26694}, {"id": 29075}, {"id": 30282}, {"id": 32042}, {"id": 34365}, {"id": 49879}, {"id": 57150}, {"id": 57300}, {"id": 57302}, {"id": 57303}, {"id": 57304}, {"id": 57305}, {"id": 57306}, {"id": 72242}]', 'https://comicvine.gamespot.com/a/uploads/screen_medium/6/62070/1633245-streetsmith.jpg');
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, '<h2>Overview</h2><p>There have been a few Lev Gleason characters that have been re-imagined at <a href="/dynamite-entertainment/4010-1859/" data-ref-id="4010-1859">Dynamite Entertainment</a> under their <a href="/project-superpowers/4050-20326/" data-ref-id="4050-20326">Project Superpowers</a> title.</p><p><b>Some of the characters that were originally published by Lev Gleason were:</b></p><ul><li>Lev Gleason Heroes</li><li>Ace Powers</li><li>Barry Lane, Adventure Hunter</li><li><a href="/bill-wayne-texas-terror/4005-73745/" data-ref-id="4005-73745">Bill Wayne</a>, Texas Terror</li><li><a href="/black-diamond/4005-12761/" data-ref-id="4005-12761">Black Diamond</a></li><li><a href="/blackout/4005-73747/" data-ref-id="4005-73747">Blackout</a> (Lev Gleason version)</li><li><a href="/bombshell/4005-24033/" data-ref-id="4005-24033">Bombshell</a> (Lev Gleason version)</li><li>Bronze Terror</li><li><a href="/captain-battle/4005-34226/" data-ref-id="4005-34226">Captain Battle</a> and Nathan Hale aka Captain Battle Jr. (Lev Gleason, Dynamite)</li><li><a href="/captain-battle-jr/4005-8135/" data-ref-id="4005-8135">Captain Battle Jr.</a>(Lev Gleason, Dynamite)</li><li><a href="/captain-fearless/4050-29429/" data-ref-id="4050-29429">Captain Fearless</a> (Lev Gleason version)</li><li><a href="/crimebuster/4005-40362/" data-ref-id="4005-40362">Crimebuster</a> and Squeeks</li><li><a href="/cloud-curtis/4005-73749/" data-ref-id="4005-73749">Cloud Curtis</a></li><li>Congo Raider</li><li><a href="/death-defying-devil/4005-25994/" data-ref-id="4005-25994">Daredevil </a>(Death Defying Devil) (Dynamite)</li><li>Dash Dillion</li><li>Deadly Dreaded Dragon</li><li>Dickie Dean, Boy Inventor</li><li>Duke Kelly, Ace Investigator</li><li>Dynamo Hill</li><li>Egghead</li><li>Flag</li><li>The Ghost (Lev Gleason, Dynamite) (Lev Gleason version)</li><li>Hot Rock Flanagan</li><li>Houdonnit the Great</li><li>Jack of Spades</li><li>Johnny Law, Sky Ranger</li><li>Kelly The Cop</li><li>Ken Keene</li><li>Kilroy</li><li>Lance Hale and Jackie</li><li>Little Wise Guys I, II</li><li>London (created by Jerry Robinson)</li><li>Meatball</li><li><a href="/mr-midnight/4005-74382/" data-ref-id="4005-74382">Mr. Midnight</a></li><li>Nightro</li><li>Pat Patriot</li><li>Pioneer, Champion of America (Lev Gleason and Dynamite)</li><li>Pirate Prince</li><li>The Planet Patrol</li><li>Presto Martin</li><li>Red American #1</li><li><a href="/red-reeves-boy-magician/4005-75871/" data-ref-id="4005-75871">Red Reeves, Boy Magician</a></li><li><a href="/rocky-x/4005-40370/" data-ref-id="4005-40370">Rocky X of the Rocketeers</a></li><li>The Saint (the only known comic book appearance of Leslie Charteris character) (Lev Gleason, Moonstone)</li><li>Scoop Scuttle</li><li>Secret Agent X-101</li><li>Silver Ranger</li><li><a href="/the-silver-streak/4005-53907/" data-ref-id="4005-53907">Silver Streak</a> and Meteor/Mercury with Whiz the Falcon (Lev Gleason and DE)</li><li>Sky Wolf</li><li><a href="/sniffer/4005-40364/" data-ref-id="4005-40364">Sniffer</a> and Jinx</li><li>Solar Patrol</li><li><a href="/spirit-man/4005-75865/" data-ref-id="4005-75865">Spirit Man</a></li><li>Swoop Storm or Swoop Smith</li><li><a href="/13/4005-51240/" data-ref-id="4005-51240">13</a> (Lev Gleason, Dynamite)</li><li>Times Square</li><li>Thun-Dohr</li><li>War Eagle</li><li>The Wasp (Lev Gleason version)</li><li>Yankee Longago</li><li>Young Robin Hood</li><li>Zongar, the Miracle Man</li></ul><p> </p><ul><li>Lev Gleason Villians</li><li><a href="/baron-doom/4005-75119/" data-ref-id="4005-75119">Baron Doom</a></li><li>Black Dragon</li><li>Boar</li><li>Bolt (Lev Gleason version)</li><li><a href="/the-claw/4005-6647/" data-ref-id="4005-6647">The Claw</a> (Lev Gleason version) (Lev Gleason, Dynamite)</li><li>Cobra Lady or Queen</li><li>Crow King</li><li><a href="/deadly-dozen/4060-56676/" data-ref-id="4060-56676">Deadly Dozen</a></li><li>Degalos</li><li>Dr. Dracula</li><li>Dr. Horror</li><li>The FFF</li><li>Friar Diablo</li><li>Frogface</li><li>Fu Tong</li><li>The Ghoul</li><li>The Green Claw</li><li>Green Dragon</li><li>The Greys</li><li>Herr Death</li><li>He-She</li><li>Hyena (Lev Gleason version)</li><li>Invisible Men</li><li><a href="/iron-jaw/4005-25992/" data-ref-id="4005-25992">Iron Jaw I</a> (Lev Gleason version)</li><li>Iron Jaw II</li><li>Iron Moles of Galaxy X</li><li>King Questionmark</li><li>Lady Killer</li><li>The Mallet</li><li>Mr. Crime</li><li>Mummy Master</li><li>Noman</li><li>Panther (Lev Gleason version)</li><li>Phantom Archer</li><li>The Professor</li><li>Prof. Blitznozzle</li><li>Prof. Skinn</li><li>Prof. Venom</li><li>Princess Sheba</li><li>Punch and Judy (Lev Gleason version)</li><li>Rodent</li><li>Scarlet Skull</li><li>Serpent</li><li>Silver Cult</li><li>Sir Satan</li><li>Skull Men</li><li>Spider (Lev Gleason version)</li><li>Spook (Lev Gleason version)</li><li>Striker</li><li>The Vacuum</li><li>The Veiled Lady (Lev Gleason, Dynamite)</li><li>Wizard (Lev Gleason version)</li><li>Wolf Carson</li></ul><p>Many of these characters have separate pages while others do not. Image Comics re-imagined Golden Age characters and revived many in their next issue project in 2009. Silver Streak Comics #24 was published in December 2009. The characters story arcs that were continued were Daredevil, Silver Streak, Kelly the Cop, The Claw, and Captain Battle. Kelly the Cop is the only character that was not also re-created at Dynamite Entertainment.</p>', '52', 'Lev Gleason', '[{"id": 58116}, {"id": 58117}, {"id": 58200}, {"id": 59003}, {"id": 60018}]', '[{"id": 886}, {"id": 942}, {"id": 943}, {"id": 1253}, {"id": 1567}, {"id": 7412}, {"id": 19424}, {"id": 25365}, {"id": 25873}, {"id": 26167}, {"id": 26742}, {"id": 39007}, {"id": 39940}, {"id": 55271}, {"id": 55867}, {"id": 58592}, {"id": 58593}, {"id": 58603}, {"id": 58604}, {"id": 58948}, {"id": 58979}, {"id": 59659}, {"id": 60515}, {"id": 63185}, {"id": 64101}, {"id": 85473}, {"id": 130180}, {"id": 149124}]', 'https://comicvine.gamespot.com/a/uploads/screen_medium/6/69951/3241120-pix_gleason_001.jpg');
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '53', 'Doumei Shuppansha', '[]', '[{"id": 120342}]', 'https://comicvine.gamespot.com/a/uploads/screen_medium/11156/111569227/9171592-doumei.jpg');
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '55', 'Sekai Bunkasha', '[]', '[{"id": 68716}]', 'https://comicvine.gamespot.com/a/uploads/screen_medium/11156/111569227/9171593-4858150111-0zUt3.jpg');
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, '<p>  The Gilberton Publisher was founded in 1942, after the parent company Elliot Publishing Company in 1941 by Albert Lewis Kanter in New York. It published comics based on older literary tales. It was sold to Frawley Corporation in 1967. Gilberto Publication went defunct in 1971.</p>', '57', 'Gilberton Publications', '[]', '[{"id": 914}, {"id": 1719}, {"id": 19484}, {"id": 22552}, {"id": 26200}, {"id": 27222}, {"id": 28659}, {"id": 28677}, {"id": 47011}, {"id": 61848}, {"id": 89222}, {"id": 106458}]', 'https://comicvine.gamespot.com/a/uploads/screen_medium/6/69951/1683591-900747_pictureparade_1_super.jpg');
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '68', 'Cat Wild', '[]', '[{"id": 160145}]', 'https://comicvine.gamespot.com/a/uploads/screen_medium/1/15776/9493112-catwild.jpg');
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '81', 'Thirdline', '[]', '[]', 'https://comicvine.gamespot.com/a/uploads/screen_medium/11122/111222211/6373148-blank.png');
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, '<p>The ability to fly is possibly the most awesome, yet common power within the pantheon of superhero culture. Flight based characters have an immediate advantage over enemies and have arguably one of the only powers without a real counter. The capability to fly represents the freedom of the individual and his or her absolute control of their world.</p>', '1', 'Flight', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, '<p>Super Stength is the iconic super power. For a character to be the ultimate brute or the supreme hero super-strength is a must.  It''s not surprising though since the traditional measure of manliness has always been strength, whether it be mental or physical. In this case, super-strength is the physical manifestation of a characters ability to assert himself over another.csdcsddscas</p>', '2', 'Super Strength', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '3', 'Super Speed', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, '<p>Agility is the ability to move nimbly or quickly. It does not neccessarily go hand in hand with super speed, which measures distance traveled over time. Agility is instead reflexive and burst-like, often coming in the form of a split-second move.</p> <p>In terms of combat, agile heros always prefer a rapid succession of short, controlled strikes. This is in contrast to a brutish strength based characters who usually rely on a smaller number of more powerful attacks. Agile Hero characters are almost always defensive in nature and disposition. Evil characters focused on agility are often tricksters and thieves who gain advantages over other characters by setting odds in their favor before a fight even begins.</p>', '4', 'Agility', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '5', 'Stamina', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '6', 'Invulnerability', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '7', 'Telepathy', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '8', 'Telekinesis', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '9', 'Intellect', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '10', 'Teleport', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '11', 'Radar Sense', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '12', 'Psychic', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, '<p>A force field is any nearly-unpenatrable container that surrounds a character for protection. It may be called upon through control over natural elements, by manifestation of mental or psionic powers or simply by sheer act of will. A character calling upon a force field is almost always in a defensive position and under a large amount of strain to keep themselves or others protected. Outside of battles, these bubbles can also serve to protect characters from the elements (such as water or space) and provide an air pocket to anyone within the field. Because of their supportive utility, force fields are often present in weaker, heavily loyal characters.</p>', '13', 'Force Field', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, '<p>Blast Power is the ability to emit, produce or discharge a burst of non-natural human energy. Normally this energy comes in the form of radiation, gas, explosives or lazer-like beams. Heros who have blast powers are almost always not able to control their gifts and often hurt their friends as much as their enemies. This normally leads to the hero having a withdrawn disposition. Blast power villans are erratic and uncontrollable, taking advantage of the unpredictable nature of their abilities to allow for quick, wide-radius attacks that result in mass destruction without target.</p>', '14', 'Blast Power', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '15', 'Healing', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '16', 'Magic', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '17', 'Weapon Master', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '18', 'Super Sight', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '19', 'Super Smell', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '20', 'Super Hearing', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '21', 'Invisibility', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '22', 'Phasing / Ghost', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, '<p>A chameleon is any character that has the ability to blend into their surrounding by changing the color and texture of their skin either through a natural ability or mechanical device. It is often confused (and at the same time paired) with shape changing, which is the ability to transform your body into another shape. Chameleons tend to be villanous more often the good, using their camoflouge skills to sneak or gain access to a restricted area. Characters with this ability tend to have mixed personalities and have a hard time defining themselves in any one way.</p>', '23', 'Chameleon', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '24', 'Shape Shifter', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '25', 'Magnetism', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '26', 'Fire Control', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '27', 'Implants', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, '<p>Feral powers are the abilities or mindset of a wild animal or animals. Ferality can exist simply as a state of mind, as a set of heightened senses or at the very extreme, the ability to transform oneself completely into a beast. Sometimes ferality comes with near-druidic powers such as the means to commune with animals (for intellegence gathering). Feral focused characters are normally potrayed as either well balanced and serene (a parallel to nature) or as wild, uncontrolable loners (the same metaphor).</p> <p>Note that characters who take on a moniker in reference to an animal (such as Batman) more often then not do not have feral abilities of any kind.</p>', '28', 'Feral', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '29', 'Psionic', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '30', 'Insanely Rich', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '31', 'Power Suit', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '32', 'Radiation', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, '<p>Elasticity is the ability to stretch a body part in a pronounced, exaggerated way. Almost always the character also has access to clothing that compensates for this skill. The elastic character''s fighting style is usually tenacious, beating their opponents by absorbing physical attacks and tiring their opponent out over the course of a battle. The typical move is to surround an enemy by wrapping oneself around them, trapping their movement.</p>', '33', 'Elasticity', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '34', 'Unarmed Combat', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, '<p>Gadgets are small mechanical tools and devices that help a hero or villian out in anyway. They can be as small as cantrips or as large as a jetpack. They are often constructed by the character themself and thereby unique and one of a kind. Gadgets are often heavily relied upon by non-powered characters to compensate and allow them to even the odds against their enenies. Because of their complexity, gadgetry is often paired with intelligent or wealthy characters.  </p>', '35', 'Gadgets', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '36', 'Weather Control', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '37', 'Divine Powers', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '38', 'Siphon Abilities', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '39', 'Size Manipulation', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '40', 'Immortal', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '49', 'Necromancy', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, NULL, '50', 'Vampirism', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, '<p>Characters with electricity as a power have control over charged particles and can generate an electric current at will. This is sometimes the result of control over a natural source of energy (such as lightning) but is more commonly manifested and expelled from the body as a result of a previous, irreversable accident. Though rare, some electric characters have control over electrons to such a degree that they can also control an electric powered machinery. Electricity is more common in villans due to the erratic, destructive use of lighting. In contrast, heros tend to have control over less harmful natural elements such as water, air and earth.</p>', '51', 'Electricity Control', 'NaN', 'NaN', NULL);
INSERT INTO pubslishers (deck, description, id, name, teams, volumes, image.screen_url) VALUES (NULL, '<p>Ice Control is awesome</p>', '52', 'Ice Control', 'NaN', 'NaN', NULL);
